1	import { useEffect, useState } from 'react';
2	import { useQueryClient } from '@tanstack/react-query';
3	import {
4	  AlertCircle,
5	  ArrowLeft,
6	  CheckCircle2,
7	  Clock,
8	  DoorOpen,
9	  ExternalLink,
10	  Eye,
11	  RefreshCw,
12	} from 'lucide-react';
13	import {
14	  Button,
15	  Card,
16	  IconButton,
17	  Logo,
18	  SelectField,
19	  Skeleton,
20	  TextField,
21	} from '@/design/components';
22	import {
23	  ACTIVE_EID_KEY,
24	  ACTIVE_SNAPSHOT_KEY,
25	  REFRESH_ACTIVE,
26	  RpcError,
27	  rpc,
28	} from '@/lib/messaging';
29	import type { PreviewResponse } from '@/lib/types';
30	import {
31	  useActiveEid,
32	  useActiveSnapshot,
33	  useAuthStatus,
34	  useDraft,
35	  usePatchDraft,
36	  usePreview,
37	  useResolveEvent,
38	  useSend,
39	  useVisitorEvents,
40	} from './hooks';
41	import { AccountMenu } from './AccountMenu';
42	import { EmptyState } from './EmptyState';
43	import { RosterRow } from './RosterRow';
44	import { PreviewSheet } from './PreviewSheet';
45	import { SignInGate } from './SignInGate';
46	
47	const isAuthError = (err: unknown) => err instanceof RpcError && !!err.needsAuth;
48	
49	export function VisitPanel() {
50	  // `storedEid` is what the content script is pointing us at (auto-follow). We
51	  // freeze the *displayed* `eid` while busy so following never switches the view
52	  // mid-action (Guard 1); edits already persist on blur (Guard 2).
53	  const storedEid = useActiveEid();
54	  const snapshot = useActiveSnapshot();
55	  const [eid, setEid] = useState<string | null>(storedEid);
56	  const auth = useAuthStatus();
57	  // Picker fuels the "open from list" empty state (and graceful fallback).
58	  const visitorEvents = useVisitorEvents(!eid && !!auth.data?.signedIn);
59	  const resolve = useResolveEvent(eid);
60	  const event = resolve.data;
61	  const draft = useDraft(event);
62	
63	  const patch = usePatchDraft(event?.iCalUid);
64	  const send = useSend(event?.iCalUid, event?.start, event?.end);
65	  const preview = usePreview(event?.iCalUid);
66	
67	  const [previewData, setPreviewData] = useState<{
68	    preview: PreviewResponse;
69	    recipient: string;
70	  } | null>(null);
71	  const [location, setLocation] = useState<string | null>(null);
72	
73	  // Guard 1: hold the current event while sending / previewing; catch up once idle.
74	  const busy = send.isPending || preview.isPending || !!previewData;
75	  useEffect(() => {
76	    if (!busy) setEid(storedEid);
77	  }, [storedEid, busy]);
78	
79	  // Post-save refresh: the background sync poll broadcasts when the active event
80	  // changed on the server (no DOM); refetch so the roster reflects saved state.
81	  const qc = useQueryClient();
82	  useEffect(() => {
83	    const listener = (msg: { type?: string }) => {
84	      if (msg?.type === REFRESH_ACTIVE) {
85	        qc.invalidateQueries({ queryKey: ['resolve'] });
86	        qc.invalidateQueries({ queryKey: ['draft'] });
87	      }
88	    };
89	    chrome.runtime.onMessage.addListener(listener);
90	    return () => chrome.runtime.onMessage.removeListener(listener);
91	  }, [qc]);
92	
93	  // Back → clear the active event/snapshot, returning to the home list.
94	  const clearActive = () =>
95	    chrome.storage.session.remove([ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY]);
96	  // Show Back in every screen except the pure home (no event, no snapshot).
97	  const back = eid || snapshot?.magicPresent ? clearActive : undefined;
98	
99	  // ---- gating states ----
100	  if (!eid) {
101	    // New, not-yet-saved visitor event (no eid, but the DOM saw the magic
102	    // address) → preview the detected guests + prompt to save.
103	    if (snapshot?.magicPresent) {
104	      return (
105	        <Shell onBack={back}>
106	          <NoticeState
107	            title="Save the event to issue passes"
108	            body="This event isn’t saved yet, so passes can’t be issued. Add your guests and save it in Google Calendar, then reopen Manage Visitors."
109	            guests={snapshot.guestEmails}
110	          />
111	        </Shell>
112	      );
113	    }
114	    return (
115	      <Shell>
116	        <EmptyState
117	          auth={auth.data}
118	          events={visitorEvents.data}
119	          loading={visitorEvents.isLoading}
120	          onPick={(ev) => {
121	            // Just point the panel at the picked event — no tab navigation. Use
122	            // "Open in Calendar" in the summary to jump to it explicitly.
123	            chrome.storage.session.set({ [ACTIVE_EID_KEY]: ev.eid });
124	          }}
125	        />
126	      </Shell>
127	    );
128	  }
129	  if (isAuthError(resolve.error) || isAuthError(draft.error)) {
130	    return <Shell onBack={back}><SignInGate /></Shell>;
131	  }
132	  if (resolve.isLoading) return <Shell onBack={back}><LoadingState label="Reading event…" /></Shell>;
133	  if (resolve.isError) {
134	    const msg = (resolve.error as Error).message;
135	    if (msg === 'NOT_SAVED') {
136	      return (
137	        <Shell onBack={back}>
138	          <NoticeState
139	            title="Save the event to issue passes"
140	            body="This event isn’t saved yet, so passes can’t be issued. Save it in Google Calendar, then reopen Manage Visitors."
141	            onRetry={() => resolve.refetch()}
142	            guests={snapshot?.guestEmails}
143	          />
144	        </Shell>
145	      );
146	    }
147	    return (
148	      <Shell onBack={back}>
149	        <ErrorState message={msg} onRetry={() => resolve.refetch()} />
150	      </Shell>
151	    );
152	  }
153	  // Event resolved but no iCalUID → the draft query can't run (would sit on a
154	  // skeleton forever). Surface it instead of hanging.
155	  if (event && !event.iCalUid) {
156	    return (
157	      <Shell onBack={back}>
158	        <NoticeState
159	          title="Can’t register from this event"
160	          body="This event has no calendar UID yet — usually because it isn’t fully saved. Save it in Google Calendar and try again."
161	          onRetry={() => resolve.refetch()}
162	        />
163	      </Shell>
164	    );
165	  }
166	  if (draft.isError) {
167	    return (
168	      <Shell onBack={back}>
169	        <ErrorState message={(draft.error as Error).message} onRetry={() => draft.refetch()} />
170	      </Shell>
171	    );
172	  }
173	  if (!draft.data) {
174	    return <Shell onBack={back}><RosterSkeleton title={event?.title} /></Shell>;
175	  }
176	
177	  const data = draft.data;
178	  const included = data.roster.filter((g) => g.include);
179	  const sentCount = data.roster.filter((g) => g.status === 'sent').length;
180	  const locValue = location ?? data.location ?? '';
181	
182	  const templates = data.emailTemplates;
183	  // One template for the whole event (engine stores per-guest; we set all guests
184	  // to the chosen key).
185	  const currentTemplate =
186	    data.roster.find((g) => g.emailTemplateKey)?.emailTemplateKey ??
187	    templates.find((t) => t.isDefault)?.key ??
188	    templates[0]?.key;
189	
190	  const patchGuest = (email: string, edit: Record<string, unknown>) =>
191	    patch.mutate({ guests: [{ email, ...edit }] });
192	
193	  const setEventTemplate = (key: string) =>
194	    patch.mutate({ guests: data.roster.map((g) => ({ email: g.email, emailTemplateKey: key })) });
195	
196	  // Review & send: render the real email for a representative included guest,
197	  // then Send/Cancel from the preview.
198	  const reviewEmail = included[0]?.email;
199	  const openReview = () => {
200	    if (!reviewEmail) return;
201	    preview.mutate(reviewEmail, {
202	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
203	    });
204	  };
205	
206	  const canSend = (included.length > 0 || data.materialized) && !send.isPending;
207	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
208	
209	  return (
210	    <Shell onBack={back}>
211	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
212	        <div
213	          className="type-label-sm text-muted"
214	          style={{ display: 'flex', alignItems: 'center', gap: 6 }}
215	        >
216	          <Eye size={13} strokeWidth={2} />
217	          Following the event open in Calendar
218	        </div>
219	        {/* Event summary */}
220	        <Card style={{ display: 'grid', gap: 'var(--space-sm)' }}>
221	          <div className="type-title-lg">{event?.title || 'Untitled event'}</div>
222	          {event?.start && (
223	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
224	              <Clock size={15} strokeWidth={2} />
225	              {formatWhen(event.start, event.end)}
226	            </div>
227	          )}
228	          {event?.rooms && event.rooms.length > 0 && (
229	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
230	              <DoorOpen size={15} strokeWidth={2} />
231	              <span className="row__ellipsis">{event.rooms.join(', ')}</span>
232	            </div>
233	          )}
234	          {event?.description && (
235	            <div
236	              className="type-label-sm text-muted"
237	              style={{
238	                whiteSpace: 'pre-wrap',
239	                maxHeight: 72,
240	                overflow: 'hidden',
241	                borderTop: '1px solid var(--color-outline-variant)',
242	                paddingTop: 'var(--space-sm)',
243	              }}
244	            >
245	              {event.description}
246	            </div>
247	          )}
248	          {eid && (
249	            <Button
250	              variant="text"
251	              icon={<ExternalLink size={16} strokeWidth={2} />}
252	              onClick={() => void rpc({ type: 'NAVIGATE_TO_EVENT', eid })}
253	              // Negative left margin = the text button's own horizontal padding,
254	              // so the label optically aligns to the card edge while the hit area
255	              // and hover state layer stay intact (MD3 text-button placement).
256	              style={{ justifySelf: 'start', marginLeft: 'calc(-1 * var(--space-md))' }}
257	            >
258	              Open in Calendar
259	            </Button>
260	          )}
261	          <TextField
262	            label="Where visitors check in"
263	            value={locValue}
264	            placeholder="e.g. Front desk, 3rd floor"
265	            onChange={(e) => setLocation(e.target.value)}
266	            onBlur={() =>
267	              locValue !== (data.location ?? '') && patch.mutate({ location: locValue })
268	            }
269	          />
270	          {templates.length >= 2 && (
271	            <SelectField
272	              label="Email template (all guests)"
273	              value={currentTemplate}
274	              onChange={(e) => setEventTemplate(e.target.value)}
275	            >
276	              {templates.map((t) => (
277	                <option key={t.key} value={t.key}>
278	                  {t.name}
279	                  {t.isDefault ? ' (default)' : ''}
280	                </option>
281	              ))}
282	            </SelectField>
283	          )}
284	        </Card>
285	
286	        {/* Roster */}
287	        <section>
288	          <div
289	            className="type-label-sm text-muted"
290	            style={{ textTransform: 'uppercase', marginBottom: 4 }}
291	          >
292	            Guests · {included.length} getting a pass
293	          </div>
294	          {data.roster.length === 0 ? (
295	            <Card className="type-body text-muted">
296	              No guests on this event yet. Add attendees in Calendar, then reopen.
297	            </Card>
298	          ) : (
299	            <Card style={{ paddingTop: 0, paddingBottom: 0 }}>
300	              {data.roster.map((g) => (
301	                <RosterRow
302	                  key={g.email}
303	                  guest={g}
304	                  onChange={(edit) => patchGuest(g.email, edit)}
305	                />
306	              ))}
307	            </Card>
308	          )}
309	        </section>
310	
311	        {/* Send result */}
312	        {send.isSuccess && <SendSummary result={send.data} />}
313	        {send.isError && (
314	          <div className="banner banner--error" role="alert">
315	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
316	            <span className="type-body">{(send.error as Error).message}</span>
317	          </div>
318	        )}
319	      </div>
320	
321	      {/* Sticky action bar */}
322	      <footer
323	        style={{
324	          padding: 'var(--space-md) var(--space-lg)',
325	          borderTop: '1px solid var(--color-outline-variant)',
326	          background: 'var(--color-surface-lowest)',
327	        }}
328	      >
329	        <Button
330	          block
331	          loading={preview.isPending}
332	          disabled={!canSend}
333	          icon={<Eye size={18} strokeWidth={2} />}
334	          onClick={openReview}
335	        >
336	          {preview.isPending
337	            ? 'Loading preview…'
338	            : `${reviewLabel}${included.length ? ` (${included.length})` : ''}`}
339	        </Button>
340	        {preview.isError && (
341	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
342	            {(preview.error as Error).message}
343	          </div>
344	        )}
345	        {sentCount > 0 && !send.isPending && (
346	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
347	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
348	          </div>
349	        )}
350	      </footer>
351	
352	      {previewData && (
353	        <PreviewSheet
354	          preview={previewData.preview}
355	          recipient={previewData.recipient}
356	          totalCount={included.length}
357	          sending={send.isPending}
358	          onSend={() =>
359	            send.mutate(undefined, { onSuccess: () => setPreviewData(null) })
360	          }
361	          onClose={() => setPreviewData(null)}
362	        />
363	      )}
364	    </Shell>
365	  );
366	}
367	
368	// ───────────────────────── sub-components ─────────────────────────
369	
370	function Shell({ children, onBack }: { children: React.ReactNode; onBack?: () => void }) {
371	  return (
372	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minWidth: 320 }}>
373	      <header
374	        style={{
375	          display: 'flex',
376	          alignItems: 'center',
377	          gap: 'var(--space-sm)',
378	          padding: 'var(--space-md) var(--space-lg)',
379	          borderBottom: '1px solid var(--color-outline-variant)',
380	          flex: '0 0 auto',
381	        }}
382	      >
383	        {onBack ? (
384	          <IconButton label="Back to events" onClick={onBack}>
385	            <ArrowLeft size={20} strokeWidth={2} />
386	          </IconButton>
387	        ) : (
388	          <Logo size={26} />
389	        )}
390	        <span className="type-title">Auxilio Visitor</span>
391	        <span style={{ flex: 1 }} />
392	        <AccountMenu />
393	      </header>
394	      <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
395	        {children}
396	      </div>
397	    </div>
398	  );
399	}
400	
401	function LoadingState({ label }: { label: string }) {
402	  return (
403	    <div
404	      style={{
405	        flex: 1,
406	        display: 'flex',
407	        flexDirection: 'column',
408	        alignItems: 'center',
409	        justifyContent: 'center',
410	        gap: 'var(--space-md)',
411	        color: 'var(--color-on-surface-variant)',
412	      }}
413	    >
414	      <span className="spinner" style={{ width: 22, height: 22 }} />
415	      <span className="type-body">{label}</span>
416	    </div>
417	  );
418	}
419	
420	function RosterSkeleton({ title }: { title?: string }) {
421	  return (
422	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
423	      <Card style={{ display: 'grid', gap: 8 }}>
424	        <span className="type-title-lg">{title || 'Loading event…'}</span>
425	        <Skeleton width="60%" />
426	      </Card>
