3	  useMutation,
4	  useQuery,
5	  useQueryClient,
6	} from '@tanstack/react-query';
7	import { ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY, rpc } from '@/lib/messaging';
8	import type {
9	  ActiveEvent,
10	  AuthStatus,
11	  DomEventSnapshot,
12	  DraftPatch,
13	  DraftResponse,
14	  VisitDraft,
15	} from '@/lib/types';
