export async function patchDraft(iCalUid: string, patch: DraftPatch | undefined): Promise<VisitDraft | null> {
  const draft = await getDraft(iCalUid);
  if (!draft) return null;
  if (patch?.location !== undefined) draft.location = patch.location;
  for (const gp of patch?.guests ?? []) {
    const guest = draft.roster.find((g) => g.email.toLowerCase() === gp.email.toLowerCase());
    if (!guest) continue;
    if (gp.include !== undefined) guest.include = gp.include;
    if (gp.name !== undefined) guest.name = gp.name;
    if (gp.phone !== undefined) guest.phone = gp.phone;
    if (gp.passTemplateKey !== undefined) guest.passTemplateKey = gp.passTemplateKey;
    if (gp.emailTemplateKey !== undefined) guest.emailTemplateKey = gp.emailTemplateKey;
  }
  await upsertDraft(draft);
  return draft;
}

/** Record created invites back onto the draft (status + invitationId) and optionally new times. */
export async function markMaterialized(
  iCalUid: string,
  passes: { visitorEmail: string; invitationId: string }[],
  times?: { eventStart?: string; eventEnd?: string },
): Promise<void> {
  const draft = await getDraft(iCalUid);
  if (!draft) return;
  for (const pass of passes) {
    const guest = draft.roster.find((g) => g.email.toLowerCase() === pass.visitorEmail.toLowerCase());
    if (guest) {
      guest.invitationId = pass.invitationId;
      guest.status = 'sent';
    }
  }
  draft.materialized = true;
  if (times?.eventStart !== undefined) draft.eventStart = times.eventStart;
  if (times?.eventEnd !== undefined) draft.eventEnd = times.eventEnd;
  await upsertDraft(draft);
}

// ─── Materialize ──────────────────────────────────────────────

/**
 * Create one visitor invite per INCLUDED guest, honoring the host's overrides.
 * Reuses `createVisitorInvite` (the shared cross-channel entry) — no logic fork.
 * Caller is responsible for cancelling any prior invites and writing the
 * `calendar_event_links` ledger row (so dedup/reschedule converge).
 */
export async function materializeDraft(
  draft: VisitDraft,
  opts: { hostName?: string; rescheduled?: boolean } = {},
): Promise<{ invitationIds: string[]; passes: PassResult[] }> {
  // Pass duration must equal the event window — never guess (decision 2026-06-17).
  const window = resolveEventWindow(draft);
  if (!window) {
    console.warn(`[VisitDraft] materialize skipped for ${draft.iCalUid}: ${EVENT_TIME_MISSING}`);
    return { invitationIds: [], passes: [] };
  }
  const { start, end } = window;

  const resolvedHost = draft.hostEmail
    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)

