/* Collapsed details row: a compact phone glimpse + an inline "Edit" affordance,
   aligned under the name so it reads as this guest's detail. Keeps cards short
   until the host actually wants to correct something. */
.guest__summary {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  min-width: 0;
  margin: var(--space-xs) 0 0 calc(36px + var(--space-md));
}
.guest__phone {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  min-width: 0;
}
.guest__edit,
.guest__done {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  flex: 0 0 auto;
  background: none;
  border: none;
  cursor: pointer;
  font: inherit;
  font-size: 12px;
  font-weight: 600;
  color: var(--color-primary);
  padding: 4px 8px;
  border-radius: var(--radius-sm);
  transition: background-color var(--motion-base) var(--motion-easing);
}
.guest__edit:hover,
.guest__done:hover { background: var(--color-surface-high); }
.guest__done { justify-self: start; margin-right: auto; }

