1	/**
2	 * Auxilio Visitor — Google Calendar add-on (card-first).
3	 *
4	 * The whole host flow lives in this card; it calls office-ops-engine over HTTPS.
5	 * Engine contract: ../office-ops-engine/spec/2026-06-16_calendar_addon_register_endpoint.md
6	 *
7	 * Apps Script (GAS, V8) — flat global scope, no imports/modules.
8	 * First version: push with clasp, then refine in the Apps Script editor (it can run
9	 * and log there; it can't be run from the monorepo).
10	 */
11	
12	// Engine base URL. Default = the local-tunnel domain (npm run backendtunnel).
13	// Must also be listed in appsscript.json → urlFetchWhitelist.
14	var ENGINE_BASE = 'https://unyearning-olympia-unclimactic.ngrok-free.dev';
15	
16	// Appointy logo embedded as a base64 data URI (gradient original from appointy.svg).
17	// Source: appointy.svg (copied from visitor-web/public/, also in this repo).
18	// Used by setImageUrl() in all card headers.
19	var ADDON_ICON_URL = 'data:image/svg+xml;base64,REDACTED';
20	
21	// Primary brand colour — used for filled buttons and accent text.
22	var BRAND_COLOR = '#92288E';
23	
24	// Circular "workspace building" avatar (Lucide `building` on a muted grey circle),
25	// shown in place of the photo avatar for INTERNAL colleagues so the host can tell at
26	// a glance who's a same-office teammate (toggle-off by default) vs an outside guest.
27	var INTERNAL_ICON_URL = 'data:image/svg+xml;base64,REDACTED';
28	
29	// ── App session (website-style sign in/out) ───────────────
30	// A Workspace add-on has no session of its own — it runs as the signed-in Google account
31	// and Google mints its token per execution, so there's nothing to "log out" at the auth
32	// layer (revoking/invalidating from inside breaks the add-on). Instead we keep OUR OWN
33	// session, exactly like a website keeps a session cookie: a per-user flag in
34	// UserProperties. Sign out sets it; every trigger gates on it and shows the signed-out
35	// card; Sign in clears it. This is a UX session, not a security revocation — the Google
36	// grant is untouched (for a real revoke the card links to "Manage access").
37	var _SESSION_SIGNED_OUT_KEY = 'auxilio.signedOut';
38	function isSignedOut_() {
39	  // A session-flag read must never throw the whole trigger — that would brick the card
40	  // (and Google's "View" button in the edit-mode drawer goes dead when the card can't
41	  // render). On any hiccup, default to signed-in so the real card still shows.
42	  try {
43	    return PropertiesService.getUserProperties().getProperty(_SESSION_SIGNED_OUT_KEY) === '1';
44	  } catch (err) {
45	    return false;
46	  }
47	}
48	function setSignedOut_() {
49	  PropertiesService.getUserProperties().setProperty(_SESSION_SIGNED_OUT_KEY, '1');
50	}
51	function clearSignedOut_() {
52	  PropertiesService.getUserProperties().deleteProperty(_SESSION_SIGNED_OUT_KEY);
53	}
54	
55	// ── Triggers ──────────────────────────────────────────────
56	// Each trigger gates on our app session first: when signed out, show the signed-out card
57	// instead of the real one (the website "you must sign in" gate).
58	function onCalendarEventOpen(e) { return [isSignedOut_() ? buildSignedOutCard_() : buildVisitorCard_(e)]; }
59	function onCalendarEventUpdate(e) { return [isSignedOut_() ? buildSignedOutCard_() : buildVisitorCard_(e)]; }
60	
61	// Serves the branded icon SVG at ?asset=logo. ContentService.MimeType.XML is the
62	// closest available type to image/svg+xml in GAS. The manifest logoUrl below points
63	// to visitor-web instead, which nginx serves with the correct image/svg+xml header.
64	function doGet(e) {
65	  if (e && e.parameter && e.parameter.asset === 'logo') {
66	    var b64 = ADDON_ICON_URL.split(',')[1];
67	    var svgText = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
68	    return ContentService.createTextOutput(svgText).setMimeType(ContentService.MimeType.XML);
69	  }
70	  return ContentService.createTextOutput('Auxilio Workspace Add-on');
71	}
72	
73	// Three-dot menu → Sign out. Sets our app-session flag, then shows the signed-out card
74	// in-panel (a universal action can only displayAddOnCards or openLink — displayAddOnCards
75	// gives the in-panel result). From here every trigger renders the gate until Sign in.
76	//
77	// This is an app-level session, NOT a Google sign-out: the grant stays (we don't revoke —
78	// invalidateAuth() wedges the add-on, and a token revoke breaks UrlFetchApp). For a real
79	// disconnect the card links to "Manage access".
80	function onSignOut(e) {
81	  setSignedOut_();
82	  return CardService.newUniversalActionResponseBuilder()
83	    .displayAddOnCards([buildSignedOutCard_()])
84	    .build();
85	}
86	
87	// "Sign in" from the gate: clear the session flag and re-render the right card for the
88	// context — the visitor card if we're inside an event, otherwise the homepage. The
89	// trigger gates will already show the real card on any later open too.
90	function onSignIn(e) {
91	  clearSignedOut_();
92	  var card = (e && e.calendar) ? buildVisitorCard_(e) : onHomepage(e);
93	  return CardService.newActionResponseBuilder()
94	    .setNavigation(CardService.newNavigation().updateCard(card))
95	    .build();
96	}
97	
98	function buildSignedOutCard_() {
99	  return CardService.newCardBuilder()
100	    .setHeader(CardService.newCardHeader()
101	      .setTitle('Auxilio Visitor')
102	      .setImageUrl(ADDON_ICON_URL))
103	    .addSection(CardService.newCardSection()
104	      .addWidget(CardService.newDecoratedText()
105	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
106	        .setText('You’re signed out')
107	        .setBottomLabel('Tap Sign in to use Auxilio again.')
108	        .setWrapText(true))
109	      .addWidget(CardService.newTextButton()
110	        .setText('Sign in')
111	        .setTextButtonStyle(CardService.TextButtonStyle.FILLED)
112	        .setBackgroundColor(BRAND_COLOR)
113	        .setOnClickAction(CardService.newAction().setFunctionName('onSignIn'))))
114	    .addSection(CardService.newCardSection()
115	      .addWidget(CardService.newDecoratedText()
116	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
117	        .setText('Remove access or switch account')
118	        .setBottomLabel('Signing out here just ends your Auxilio session. To fully disconnect Auxilio from your Google account or switch accounts, open your Google permissions.')
119	        .setWrapText(true))
120	      .addWidget(CardService.newTextButton()
121	        .setText('Manage access')
122	        .setOpenLink(CardService.newOpenLink()
123	          .setUrl('https://myaccount.google.com/permissions'))))
124	    .build();
125	}
126	
127	function onHomepage(e) {
128	  if (isSignedOut_()) return buildSignedOutCard_();
129	
130	  var introSection = CardService.newCardSection()
131	    .addWidget(CardService.newTextParagraph()
132	      .setText('Open a calendar event and add guest to register visitor passes.'));
133	
134	  var howSection = CardService.newCardSection()
135	    .setHeader('How it works')
136	    .addWidget(CardService.newDecoratedText()
137	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
138	      .setText('Choose who gets a pass')
139	      .setBottomLabel('Toggle guests on or off from the event\'s attendee list.')
140	      .setWrapText(true))
141	    .addWidget(CardService.newDecoratedText()
142	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.INVITE))
143	      .setText('Review and send')
144	      .setBottomLabel('Edit names and phone numbers, preview the invite email, then send.')
145	      .setWrapText(true))
146	    .addWidget(CardService.newDecoratedText()
147	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.TICKET))
148	      .setText('Manage anytime')
149	      .setBottomLabel('Cancel or resend passes by toggling them off and on.')
150	      .setWrapText(true));
151	
152	  var autoSyncSection = CardService.newCardSection()
153	    .addWidget(CardService.newDecoratedText()
154	      .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.STAR))
155	      .setText('Auto-sync')
156	      .setBottomLabel('Move or cancel a meeting event and passes update automatically.')
157	      .setWrapText(true));
158	
159	  return CardService.newCardBuilder()
160	    .setHeader(CardService.newCardHeader()
161	      .setTitle('Auxilio Visitor')
162	      .setSubtitle('Manage visitors from your calendar')
163	      .setImageUrl(ADDON_ICON_URL))
164	    .addSection(introSection)
165	    .addSection(howSection)
166	    .addSection(autoSyncSection)
167	    .build();
168	}
169	
170	// ── Engine HTTP ───────────────────────────────────────────
171	function engineFetch_(path, method, payload) {
172	  var options = {
173	    method: method,
174	    contentType: 'application/json',
175	    muteHttpExceptions: true,
176	    headers: {
177	      Authorization: 'Bearer ' + ScriptApp.getIdentityToken(),
178	      'ngrok-skip-browser-warning': 'true'
179	    }
180	  };
181	  if (payload) options.payload = JSON.stringify(payload);
182	  // muteHttpExceptions only suppresses non-2xx HTTP *statuses*; a DNS/connection
183	  // failure (e.g. the engine tunnel is down) still THROWS. Left unhandled that
184	  // propagates out of the trigger as Google's generic "Unspecified error invoking
185	  // the add-on". Catch it and return a synthetic 0 so callers render a real error
186	  // card instead. _lastEngineErr carries the reason for the card/diagnostics.
187	  var res;
188	  try {
189	    res = UrlFetchApp.fetch(ENGINE_BASE + path, options);
190	  } catch (err) {
191	    _lastEngineErr = (err && err.message ? String(err.message) : String(err)).slice(0, 140);
192	    return { code: 0, json: {} };
193	  }
194	  _lastEngineErr = '';
195	  var json = {};
196	  try { json = JSON.parse(res.getContentText()); } catch (err) {}
197	  return { code: res.getResponseCode(), json: json };
198	}
199	var _lastEngineErr = '';
200	
201	// Resolve attendees + (best-effort) iCalUID/title/times for the open event.
202	// Attendees come from the add-on payload (currentEventAccess) — no API call needed.
203	// The Calendar API lookup enriches with the canonical iCalUID + title/times so the
204	// engine dedups with the .ics/OAuth paths; if it fails we fall back to the event id
205	// as the key so the flow still works.
206	function loadEvent_(e) {
207	  var cal = e.calendar || {};
208	  var calendarId = cal.calendarId;
209	  var eventId = cal.id;
210	  var payloadAtt = cal.attendees || [];
211	  var info = {
212	    iCalUid: eventId,
213	    providerEventId: eventId,
214	    keySource: 'eventId',
215	    title: '',
216	    start: null,
217	    end: null,
218	    attendees: mapAttendees_(payloadAtt),
219	    debug: ''
220	  };
221	  var ev = fetchEventWithRetry_(calendarId, eventId);
222	  info.gotEvent = !!ev;
223	  if (ev) {
224	    if (ev.iCalUID) { info.iCalUid = ev.iCalUID; info.keySource = 'iCalUID'; }
225	    info.title = ev.summary || '';
226	    info.start = ev.start ? (ev.start.dateTime || ev.start.date) : null;
227	    info.end = ev.end ? (ev.end.dateTime || ev.end.date) : null;
228	    var apiAtt = mapAttendees_(ev.attendees);
229	    if (info.attendees.length === 0 && apiAtt.length > 0) info.attendees = apiAtt;
230	  }
231	  info.debug = 'got=' + (!!ev) + ' key=' + info.keySource + ' start=' + (info.start || 'null') +
232	    ' cal=' + (calendarId || '?') + ' guests=' + info.attendees.length +
233	    (info.gotEvent ? '' : ' err=' + (_lastEventFetchErr || 'none'));
234	  return info;
235	}
236	
237	// Resolve the event from the Calendar API, tolerating transient 404s. A freshly
238	// created event is eventually-consistent — Events.get can 404 for a second or two
239	// after the user adds it — and this is our ONLY source of event start/end (the add-on
240	// payload carries attendees but no times). So a miss here means a draft saved without
241	// times and a send that fails with EVENT_TIME_MISSING. Retry with backoff (~2.7s
242	// total) across the event's calendar and the primary calendar. Returns the event or null.
243	var _lastEventFetchErr = '';
244	function fetchEventWithRetry_(calendarId, eventId) {
245	  _lastEventFetchErr = '';
246	  var targets = [];
247	  if (calendarId) targets.push(calendarId);
248	  if (calendarId !== 'primary') targets.push('primary');
249	  // Common case (a saved, propagated event) returns on the first get with no sleep.
250	  // The retries only cover a just-created event that's still eventually-consistent;
251	  // ~0.85s total is enough to catch the usual ~1s propagation without making every
252	  // unsaved-event open feel sluggish (the card shows a "save first" banner anyway,
253	  // and onSaveAndSend re-resolves the time before the actual send).
254	  var backoffs = [250, 600]; // waits AFTER attempts 0,1 (3 attempts total)
255	  for (var attempt = 0; attempt <= backoffs.length; attempt++) {
256	    for (var t = 0; t < targets.length; t++) {
257	      try {
258	        var ev = Calendar.Events.get(targets[t], eventId);
259	        if (ev) return ev;
260	      } catch (err) {
261	        // Capture WHY (auth/scope vs 404) — a persistent failure here is the root of
262	        // "Could not read the event time"; the message tells us scope vs not-found.
263	        _lastEventFetchErr = (err && err.message ? String(err.message) : String(err)).slice(0, 140);
264	      }
265	    }
266	    if (attempt < backoffs.length) Utilities.sleep(backoffs[attempt]);
267	  }
268	  return null;
269	}
270	
271	// Per-guest avatar: Gravatar keyed on the email (real photo if they have one),
272	// falling back to a coloured initials avatar (ui-avatars) when they don't. Rendered
273	// as a circular image icon. Image URLs are fetched by Google's client, so they
274	// don't need urlFetchWhitelist.
275	function avatarIcon_(email, name) {
276	  var initials = (name || email || '?').trim().charAt(0).toUpperCase() || '?';
277	  var fallback = 'https://ui-avatars.com/api/?name=' + encodeURIComponent(initials) +
278	    '&size=64&background=92288E&color=ffffff&bold=true';
279	  var url = 'https://www.gravatar.com/avatar/' + md5Hex_((email || '').trim().toLowerCase()) +
280	    '?s=64&d=' + encodeURIComponent(fallback);
281	  return CardService.newIconImage()
282	    .setIconUrl(url)
283	    .setImageCropType(CardService.ImageCropType.CIRCLE);
284	}
285	
286	// Circular building icon for internal colleagues (see INTERNAL_ICON_URL).
287	function buildingIcon_() {
288	  return CardService.newIconImage()
289	    .setIconUrl(INTERNAL_ICON_URL)
290	    .setImageCropType(CardService.ImageCropType.CIRCLE);
291	}
292	
293	// Minimal MD5 → lowercase hex (Gravatar needs MD5 of the email).
294	function md5Hex_(str) {
295	  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.MD5, str, Utilities.Charset.UTF_8);
296	  var hex = '';
297	  for (var i = 0; i < bytes.length; i++) {
298	    var b = (bytes[i] + 256) % 256;
299	    hex += (b < 16 ? '0' : '') + b.toString(16);
300	  }
301	  return hex;
302	}
303	
304	function mapAttendees_(list) {
305	  return (list || [])
306	    .filter(function (a) { return a && a.email && !a.self && !a.organizer && !a.resource; })
307	    .map(function (a) {
308	      // Google often sets displayName = the email for non-contacts → treat as no name.
309	      var nm = (a.displayName && a.displayName !== a.email) ? a.displayName : '';
310	      return { email: a.email, name: nm };
311	    });
312	}
313	
314	// ── Card helpers ──────────────────────────────────────────
315	
316	function statusLabel_(g) {
317	  if (g.status === 'sent')      return '<font color="#34a853">Pass sent</font>';
318	  if (g.status === 'cancelled') return '<font color="#ea4335">Cancelled — toggle on to resend</font>';
319	  if (g.include === false) {
320	    // Internal colleagues are off by default ON PURPOSE — say so instead of a bare
321	    // "No pass" that reads like something's missing.
322	    return g.internal
323	      ? '<font color="#5f6368">Internal</font>'
324	      : '<font color="#9aa0a6">No pass</font>';
325	  }
326	  return '<font color="' + BRAND_COLOR + '">Will get a pass</font>';
327	}
328	
329	// Returns a coloured stat line: "3 guests · 2 sent · 1 pending"
330	function buildStatLine_(roster) {
331	  var total = roster.length;
332	  var sent = 0, pending = 0, cancelled = 0;
333	  for (var i = 0; i < roster.length; i++) {
334	    var g = roster[i];
335	    if (g.status === 'sent') sent++;
336	    else if (g.status === 'cancelled') cancelled++;
337	    else if (g.include !== false) pending++;
338	  }
339	  var parts = [total + (total === 1 ? ' guest' : ' guests')];
340	  if (sent)      parts.push('<font color="#34a853">' + sent + ' sent</font>');
341	  if (pending)   parts.push('<font color="' + BRAND_COLOR + '">' + pending + ' pending</font>');
342	  if (cancelled) parts.push('<font color="#ea4335">' + cancelled + ' cancelled</font>');
343	  return parts.join('  ·  ');
344	}
345	
346	// The email template currently in effect for the batch: the first included guest's
347	// chosen template (templates are stored per-guest but picked once for the whole send),
348	// or '' to let the confirm card pre-select the engine default.
349	function currentTemplateKey_(roster) {
350	  for (var i = 0; i < roster.length; i++) {
351	    var g = roster[i];
352	    if (g.include !== false && g.emailTemplateKey) return g.emailTemplateKey;
353	  }
354	  return '';
355	}
356	
357	// Returns "Meeting title · Wed 18 Jun, 3:00 PM" for the card subtitle.
358	function formatEventSubtitle_(ev) {
359	  if (!ev.start) return ev.title || '';
360	  try {
361	    var d = new Date(ev.start);
362	    var day  = d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' });
363	    var time = d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
364	    var datePart = day + ', ' + time;
365	    return ev.title ? ev.title + '  ·  ' + datePart : datePart;
366	  } catch (err) {
367	    return ev.title || '';
368	  }
369	}
370	
371	// ── Main card ─────────────────────────────────────────────
372	function buildVisitorCard_(e) {
373	  // Fast path: no external guests in the payload → render immediately without any
374	  // network call. Keeps empty events snappy so the loader never lingers.
375	  var cal = e.calendar || {};
376	  if (mapAttendees_(cal.attendees).length === 0) {
377	    return CardService.newCardBuilder()
378	      .setHeader(CardService.newCardHeader()
379	        .setTitle('Visitor passes')
380	        .setImageUrl(ADDON_ICON_URL))
381	      .addSection(CardService.newCardSection()
382	        .addWidget(CardService.newDecoratedText()
383	          .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.PERSON))
384	          .setText('No guests yet')
385	          .setBottomLabel('Add a guest to this event.')
386	          .setWrapText(true)))
387	      .build();
388	  }
389	
390	  var ev = loadEvent_(e);
391	  if (!ev.iCalUid) return errorCard_('No event id in payload (' + ev.debug + ') — save the event, then reopen.');
392	
393	  var organizerEmail = (cal.organizer && cal.organizer.email) || '';
394	  var res = engineFetch_('/api/visitor/calendar/addon/draft', 'POST', {
395	    iCalUid: ev.iCalUid, providerEventId: ev.providerEventId, organizerEmail: organizerEmail,
