551	// ── Actions ───────────────────────────────────────────────
552	// Same derivation the engine uses, so we can tell an auto-derived name from a real one.
553	function cardDeriveName_(email) {
554	  var local = (email.split('@')[0] || email);
555	  return local.replace(/[._-]+/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); }).trim() || email;
556	}
557	
558	// Contact-name lookups are the heaviest part of a fresh card open, so we cache each
559	// resolved name (incl. "no match", to avoid re-querying non-contacts) per user in
560	// CacheService. A repeat open of any event with the same guest is then zero network.
561	// TTL 6h: long enough that a meeting's roster never re-pays, short enough to pick up
562	// a newly-added contact within a day. Key is lowercased email (per-user cache).
563	var _CONTACT_CACHE_TTL = 21600; // 6h, in seconds
564	function _contactCacheKey_(email) { return 'cn_' + (email || '').toLowerCase(); }
565	
566	// searchContacts/otherContacts.search need a one-time warmup (empty query) so the
567	// server-side index is populated before the real query. Done once per execution.
568	var _peopleWarmed = false;
569	function warmPeople_(headers, base) {
570	  if (_peopleWarmed) return;
571	  _peopleWarmed = true;
572	  try {
573	    UrlFetchApp.fetchAll([
574	      { url: base + 'people:searchContacts?query=&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true },
575	      { url: base + 'otherContacts:search?query=&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true }
576	    ]);
577	  } catch (err) {}
578	  Utilities.sleep(120); // brief settle so the freshly-warmed index is queryable
579	}
580	
581	// Pull the display name for `email` out of a People search response, or '' if no
582	// result actually matches that address.
583	function extractPeopleName_(resp, email) {
584	  if (!resp || resp.getResponseCode() !== 200) return '';
585	  var results;
586	  try { results = (JSON.parse(resp.getContentText()).results) || []; }
587	  catch (err) { return ''; }
588	  for (var i = 0; i < results.length; i++) {
589	    var person = results[i].person || {};
590	    var emails = person.emailAddresses || [];
591	    var match = emails.some(function (em) { return (em.value || '').toLowerCase() === email.toLowerCase(); });
592	    if (match && person.names && person.names.length) return person.names[0].displayName || '';
593	  }
594	  return '';
595	}
596	
597	// Resolve display names for several emails in ONE parallel batch (searchContacts +
598	// otherContacts.search per email via UrlFetchApp.fetchAll) instead of 2 serial calls
599	// each. Returns a map of lowercased email → name (absent when no contact matched).
600	function batchResolveNames_(emails) {
601	  var out = {};
602	  if (!emails.length) return out;
603	  var headers = { Authorization: 'Bearer ' + ScriptApp.getOAuthToken() };
604	  var base = 'https://people.googleapis.com/v1/';
605	  warmPeople_(headers, base);
606	  var requests = [], meta = [];
607	  for (var i = 0; i < emails.length; i++) {
608	    var q = encodeURIComponent(emails[i]);
609	    requests.push({ url: base + 'people:searchContacts?query=' + q + '&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true });
610	    meta.push(emails[i]);
611	    requests.push({ url: base + 'otherContacts:search?query=' + q + '&readMask=names,emailAddresses', headers: headers, muteHttpExceptions: true });
612	    meta.push(emails[i]);
613	  }
614	  var responses;
615	  try { responses = UrlFetchApp.fetchAll(requests); }
616	  catch (err) { return out; }
617	  for (var r = 0; r < responses.length; r++) {
618	    var key = meta[r].toLowerCase();
619	    if (out[key]) continue; // already matched from this email's other source
620	    var name = extractPeopleName_(responses[r], meta[r]);
621	    if (name) out[key] = name;
622	  }
623	  return out;
624	}
625	
626	// For each guest whose name is still auto-derived, fill in the real contact name and
627	// PATCH it onto the draft (so the engine remembers it too). Cache hits skip the
628	// network entirely; only genuine misses hit the People API, all in one batch. Mutates
629	// roster.
630	function resolveAndStoreNames_(iCalUid, roster) {
631	  var cache = CacheService.getUserCache();
632	  var pending = [];   // roster entries still showing an auto-derived name
633	  var toLookup = [];  // emails with no cached answer → need a network lookup
634	  for (var i = 0; i < roster.length; i++) {
635	    var g = roster[i];
636	    if (g.name && g.name !== cardDeriveName_(g.email)) continue; // already a real name
637	    pending.push(g);
638	    var cached = cache.get(_contactCacheKey_(g.email));
639	    if (cached === null) toLookup.push(g.email); // unknown → look up
640	    else if (cached) g.name = cached;            // '' = known non-contact, leave derived
641	  }
642	
643	  if (toLookup.length) {
644	    var resolved = batchResolveNames_(toLookup);
645	    for (var j = 0; j < toLookup.length; j++) {
646	      var name = resolved[toLookup[j].toLowerCase()] || '';
647	      cache.put(_contactCacheKey_(toLookup[j]), name, _CONTACT_CACHE_TTL); // cache hits AND misses
648	    }
649	    for (var k = 0; k < pending.length; k++) {
650	      var pg = pending[k];
651	      var rn = resolved[pg.email.toLowerCase()];
652	      if (rn) pg.name = rn; // reflect immediately in this render
653	    }
654	  }
655	
656	  var patches = [];
657	  for (var m = 0; m < pending.length; m++) {
658	    var p = pending[m];
659	    if (p.name && p.name !== cardDeriveName_(p.email)) patches.push({ email: p.email, name: p.name });
660	  }
661	  if (patches.length) {
662	    engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: patches } });
663	  }
664	}
