784	function onSaveAndSend(e) {
785	  var iCalUid = e.parameters.iCalUid;
786	  // Toggles/names/phones were already persisted by onReviewSend on the ROSTER card.
787	  // This runs from the CONFIRM card, which has none of those widgets — re-running
788	  // patchFromForm_ here would read empty inputs and wipe every guest to include=false
789	  // (the "No changes / No pass" bug). Only the (optional) template picker lives here.
790	  patchTemplateFromForm_(iCalUid, e);
791	  // Re-resolve event times here and send them along: if the draft-open missed them
792	  // (flaky Events.get on a just-created event), the draft would have no start/end and
793	  // the send would fail with EVENT_TIME_MISSING. Passing fresh times lets the engine
794	  // self-correct the draft instead of forcing the host to reopen.
795	  var ev = loadEvent_(e);
796	  // Times come only from Calendar.Events.get (the payload has none). If we still can't
797	  // read them, say exactly why instead of the engine's generic message — `got=false`
798	  // means the API call itself failed (scope/Advanced-Service/permission, not a timing
799	  // blip); `got=true start=null` means the event genuinely has no start.
800	  if (!ev.start || !ev.end) {
801	    // A 'Not Found' from Calendar.Events.get means the event isn't saved/propagated
802	    // yet — the panel shows attendees from the payload, but the event record (the only
803	    // source of start/end) doesn't exist server-side. Tell the host plainly.
804	    if (ev.debug.indexOf('Not Found') >= 0 || !ev.gotEvent) {
805	      return notify_('Save the event first (click Save), then reopen this panel and send. The pass time comes from the saved event.');
806	    }
807	    return notify_('Could not read the event time. Diagnostic: ' + ev.debug);
808	  }
809	  var res = engineFetch_('/api/visitor/calendar/addon/send', 'POST', {
810	    iCalUid: iCalUid, start: ev.start, end: ev.end
811	  });
812	  var msg;
813	  if (res.code === 200) {
814	    var sent = (res.json.created || []).length;
815	    var cancelled = (res.json.cancelled || []).length;
816	    var failed = res.json.failed || [];
817	    if (failed.length) {
818	      // Surface WHY a pass couldn't be sent (most often: event time in the past)
819	      // instead of silently leaving the guest pending.
820	      var reason = (failed[0] && failed[0].reason) || 'could not be sent';
821	      msg = "Couldn't send " + failed.length + ' pass' + (failed.length > 1 ? 'es' : '') + ': ' + reason;
822	    } else {
823	      var parts = [];
824	      if (sent) parts.push(sent + ' sent');
825	      if (cancelled) parts.push(cancelled + ' cancelled');
826	      msg = parts.length ? ('Passes updated: ' + parts.join(', ') + '.') : 'No changes.';
827	    }
828	  } else if (res.code === 0) {
829	    msg = 'Can’t reach the engine — passes were not sent. Try again in a moment.';
830	  } else {
831	    msg = 'Update failed (' + res.code + ').';
832	  }
833	  // Re-render so the card switches to Manage mode and shows fresh statuses.
834	  return CardService.newActionResponseBuilder()
835	    .setNotification(CardService.newNotification().setText(msg))
836	    .setNavigation(CardService.newNavigation().updateCard(buildVisitorCard_(e)))
837	    .build();
838	}
