857	      .setUrl(url)
858	      .setOpenAs(CardService.OpenAs.OVERLAY)
859	      .setOnClose(CardService.OnClose.NOTHING))
860	    .build();
861	}
862	
863	// Mint a preview-html URL (with a fresh signed token) at card-build time so the
864	// "Preview email" button can carry it via setOpenLink and open on the click itself
865	// — dodging the popup blocker that hits round-trip (setOnClickAction) opens. Returns
866	// '' if we can't mint a token, so the caller can fall back to the onPreview handler.
867	function previewUrl_(iCalUid, visitorEmail) {
868	  if (!iCalUid || !visitorEmail) return '';
869	  var pv = engineFetch_('/api/visitor/calendar/addon/preview', 'POST', { iCalUid: iCalUid, visitorEmail: visitorEmail });
870	  if (pv.code !== 200 || !pv.json.previewToken) return '';
871	  return ENGINE_BASE + '/api/visitor/calendar/addon/preview-html?t=' + encodeURIComponent(pv.json.previewToken);
872	}
873	
874	// Template dropdown changed on the confirm card: persist the new choice to the draft.
875	// The Preview link is pre-baked and the token is template-agnostic (preview-html reads
876	// the draft live), so persisting here is all that's needed — no card rebuild, no new
877	// URL. Stay silent on success; only speak up if the persist failed.
878	function onConfirmTemplateChange(e) {
879	  var res = patchTemplateFromForm_(e.parameters.iCalUid, e);
880	  if (res && res.code && res.code !== 200) {
881	    return notify_('Could not switch the template — try again before previewing or sending.');
882	  }
883	  return CardService.newActionResponseBuilder().build();
884	}
885	
886	// ── Helpers ───────────────────────────────────────────────
887	function patchFromForm_(iCalUid, e) {
888	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
889	  var inputs = formInputs_(e);
890	  // The template picker lives on the confirm card only; it's absent (empty) when this
891	  // runs from the roster card, so we leave emailTemplateKey untouched there. One choice
892	  // applies to the whole batch (templates are stored per-guest).
893	  var tmpl = formValue_(inputs['email_template']);
894	  var guests = emails.map(function (em) {
895	    var g = {
896	      email: em,
897	      include: formValue_(inputs['inc_' + em]) === 'on', // OFF switches are absent → false
898	      name: formValue_(inputs['name_' + em]),
899	      phone: formValue_(inputs['phone_' + em])
900	    };
901	    if (tmpl) g.emailTemplateKey = tmpl;
902	    return g;
903	  });
904	  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
905	}
906	
907	// Confirm-card patch: persist ONLY the batch email-template choice. The confirm card
908	// has no include/name/phone widgets, so we must not derive (and overwrite) those here
909	// — only `email_template` is present. Absent/no-change picker → no-op.
910	function patchTemplateFromForm_(iCalUid, e) {
911	  var tmpl = formValue_(formInputs_(e)['email_template']);
912	  if (!tmpl) return; // no picker shown, or nothing to change
913	  var emails = (e.parameters.emails || '').split(',').filter(Boolean_);
914	  if (!emails.length) return;
915	  var guests = emails.map(function (em) { return { email: em, emailTemplateKey: tmpl }; });
916	  return engineFetch_('/api/visitor/calendar/addon/draft', 'PATCH', { iCalUid: iCalUid, patch: { guests: guests } });
917	}
918	
919	function formInputs_(e) {
920	  return (e.commonEventObject && e.commonEventObject.formInputs) || {};
921	}
922	function formValue_(input) {
923	  if (input && input.stringInputs && input.stringInputs.value && input.stringInputs.value.length) {
924	    return input.stringInputs.value[0];
925	  }
926	  return '';
927	}
928	function Boolean_(x) { return !!x; }
929	
930	function textPreview_(json) {
931	  var t = json.text || json.html || '';
932	  t = t.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
933	  return t.length > 1200 ? t.substring(0, 1200) + '…' : t;
934	}
935	
936	function notify_(msg) {
937	  return CardService.newActionResponseBuilder()
938	    .setNotification(CardService.newNotification().setText(msg))
939	    .build();
940	}
941	
942	function errorCard_(msg) {
943	  return CardService.newCardBuilder()
944	    .setHeader(CardService.newCardHeader()
945	      .setTitle('Something went wrong')
946	      .setImageUrl(ADDON_ICON_URL))
947	    .addSection(CardService.newCardSection()
948	      .addWidget(CardService.newDecoratedText()
949	        .setStartIcon(CardService.newIconImage().setIcon(CardService.Icon.DESCRIPTION))
950	        .setText(msg)
951	        .setWrapText(true)))
952	    .build();
953	}
954

