/**
 * Per-user Google Calendar OAuth — connect flow + connection store.
 *
 * Canonical design: Planning-docs/2026-06-12_calendar_to_visitor_invite_research.md §8.
 *
 * A host connects once (one tap from the Slack App Home / first-DM button). We store
 * a long-lived refresh token in `calendar_connections`, then `calendar-sync.ts` polls
 * their calendar and feeds events into `ingestCalendarEvent` as source 'oauth'.
 *
 * Reuses the admin-SSO OAuth client credentials (GOOGLE_OAUTH_*) — fine for
 * internal-first (each flow requests only its own scopes; that client already
 * carried calendar-read). Scope is a single `calendar.events` (read+write):
 * read powers the lifecycle watch (move/delete of tracked events); write powers
 * creating the event on a Slack-self-host's calendar (D8). calendar.events is
 * "sensitive", NOT restricted → still no CASA. Never add Gmail/Drive.
 *
 * For a non-expiring refresh token the OAuth app must be "In production" (Testing =
 * 7-day expiry). See research doc §8.
 */

import { createHmac, timingSafeEqual } from 'crypto';
import { google } from 'googleapis';
import { getDb } from '../../lib/database';
import { googleOauth as googleOauthConfig } from '../../lib/config';

const STATE_TTL_MS = 15 * 60 * 1000;
const DEFAULT_TENANT_ID = 'appointy';

/**
 * Single scope: calendar.events (READ+WRITE). Read = the lifecycle watch; write =
 * creating the event on a Slack-self-host's calendar (D8, so it's trackable + the
 * guest is invited natively). "Sensitive", NOT restricted → no CASA. Contacts were
 * dropped: name resolution lives in the add-on (its own People API) + the invite
 * forms; the poll no longer creates invites, so backend contacts is dead. Never
 * add Gmail/Drive here.
 */
const CALENDAR_SCOPES = [
  'https://www.googleapis.com/auth/calendar.events',
];

/**
 * Bump whenever CALENDAR_SCOPES changes. NOTE: this does NOT force a reconnect —
 * `listScopeStaleConnections` only *flags* older-version connections (their token
 * still covers calendar-read, so the watch keeps working). We prompt the write
 * upgrade lazily (only when a Slack host needs to create an event). Connections at
 * this version are write-capable (`calendar.events`); older ones are read-only.
 */
export const CURRENT_SCOPE_VERSION = 'v3-events-rw';

/**
 * A connection can CREATE calendar events (write) once it's been granted the
 * current `calendar.events` scope. Older read-only connections return false →
 * the Slack create-from-form flow prompts a lazy reconnect instead of writing.
 */
export function isWriteCapableConnection(conn: { scope_version?: string | null } | null | undefined): boolean {
  return conn?.scope_version === CURRENT_SCOPE_VERSION;
}

/** True when the host has a live, write-capable connection (can create events via OAuth). */
export async function isHostWriteCapable(hostEmail: string): Promise<boolean> {
  const conn = await getCalendarConnection(hostEmail).catch(() => null);
  return !!conn && conn.status === 'connected' && !!conn.refresh_token && isWriteCapableConnection(conn);
}

function stateSecret(): string {
  return process.env.VISITOR_ADMIN_SESSION_SECRET
    ?? process.env.VISITOR_ADMIN_SECRET
    ?? 'calendar-oauth-state-fallback';
}

export function isCalendarOAuthConfigured(): boolean {
  return !!(googleOauthConfig.clientId() && googleOauthConfig.clientSecret() && googleOauthConfig.publicOrigin());
}

function callbackUrl(): string {
  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
  if (!origin) throw new Error('GOOGLE_OAUTH_PUBLIC_ORIGIN is not configured');
  return `${origin}/api/visitor/calendar/connect/callback`;
}

function buildClient() {
  const clientId = googleOauthConfig.clientId();
  const clientSecret = googleOauthConfig.clientSecret();
  if (!clientId || !clientSecret) throw new Error('Google OAuth client credentials are not configured');
  return new google.auth.OAuth2(clientId, clientSecret, callbackUrl());
}

// ─── Signed state (carries host binding, no server-side store) ────────

export interface CalendarStatePayload {
  email: string;
  slackUserId?: string;
}

export function issueCalendarState(payload: CalendarStatePayload): string {
  const body = Buffer.from(JSON.stringify({ ...payload, exp: Date.now() + STATE_TTL_MS })).toString('base64url');
  const sig = createHmac('sha256', stateSecret()).update(body).digest('base64url');
  return `${body}.${sig}`;
}

export function verifyCalendarState(state: string | undefined): CalendarStatePayload | null {
  if (!state) return null;
  const parts = state.split('.');
  if (parts.length !== 2) return null;
  const [body, sig] = parts as [string, string];
  const expected = createHmac('sha256', stateSecret()).update(body).digest('base64url');
  const a = Buffer.from(sig, 'utf8');
  const b = Buffer.from(expected, 'utf8');
  if (a.length !== b.length || !timingSafeEqual(a, b)) return null;
  try {
    const parsed = JSON.parse(Buffer.from(body, 'base64url').toString('utf8')) as CalendarStatePayload & { exp: number };
    if (!parsed.exp || parsed.exp < Date.now() || !parsed.email) return null;
    return { email: parsed.email.toLowerCase(), slackUserId: parsed.slackUserId };
  } catch {
    return null;
  }
}

/** The browser URL the Slack button points at (our /start, not Google directly). */
export function connectStartUrl(payload: CalendarStatePayload): string {
  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
  return `${origin}/api/visitor/calendar/connect/start?s=${encodeURIComponent(issueCalendarState(payload))}`;
}

/** URL for the Slack "Disconnect" button → our disconnect route. */
export function disconnectUrl(payload: CalendarStatePayload): string {
  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
  return `${origin}/api/visitor/calendar/connect/disconnect?s=${encodeURIComponent(issueCalendarState(payload))}`;
}

/** Google consent URL. login_hint pre-selects the host's account (research doc §8). */
export function buildCalendarAuthUrl(state: string, loginHint?: string): string {
  const client = buildClient();
  return client.generateAuthUrl({
    access_type: 'offline',   // required for a refresh token
    prompt: 'consent',         // guarantees refresh token even on re-auth
    scope: CALENDAR_SCOPES,
    state,
    include_granted_scopes: true,
    ...(loginHint ? { login_hint: loginHint } : {}),
  });
}

export interface CalendarTokenResult {
  refreshToken?: string;
}

export async function exchangeCalendarCode(code: string): Promise<CalendarTokenResult> {
  const client = buildClient();
  const { tokens } = await client.getToken(code);
  return { refreshToken: tokens.refresh_token ?? undefined };
}

/** OAuth2 client bound to a host's stored refresh token (mints access tokens). */
export function clientForRefreshToken(refreshToken: string) {
  const client = buildClient();
  client.setCredentials({ refresh_token: refreshToken });
  return client;
}

// ─── Connection store ─────────────────────────────────────────

export interface CalendarConnection {
  host_email: string;
  tenant_id: string;
  provider: string;
  auth_mode: string;
  refresh_token: string | null;
  sync_token: string | null;
  slack_user_id: string | null;
  status: string;
  scope_version: string | null;
}

export async function getCalendarConnection(email: string): Promise<CalendarConnection | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM calendar_connections WHERE host_email = ? LIMIT 1`,
    args: [email.toLowerCase()],
  });
  return (result.rows[0] as unknown as CalendarConnection) ?? null;
}

export async function isCalendarConnected(email: string): Promise<boolean> {
  const conn = await getCalendarConnection(email);
  return !!conn && conn.status === 'connected' && !!conn.refresh_token;
}

export async function upsertCalendarConnection(input: {
  email: string;
  refreshToken?: string;
  slackUserId?: string;
  tenantId?: string;
}): Promise<void> {
  const db = await getDb();
  // Only overwrite refresh_token when Google actually returned one (re-consent
  // without a new token shouldn't clobber the stored one).
  await db.execute({
    sql: `INSERT INTO calendar_connections (host_email, tenant_id, provider, auth_mode, refresh_token, slack_user_id, status, scope_version, connected_at)
          VALUES (?, ?, 'google', 'oauth', ?, ?, 'connected', ?, now()::text)
          ON CONFLICT (host_email) DO UPDATE SET
            status = 'connected',
            slack_user_id = COALESCE(EXCLUDED.slack_user_id, calendar_connections.slack_user_id),
            refresh_token = COALESCE(EXCLUDED.refresh_token, calendar_connections.refresh_token),
            scope_version = EXCLUDED.scope_version,
            connected_at = now()::text`,
    args: [
      input.email.toLowerCase(),
      input.tenantId ?? DEFAULT_TENANT_ID,
      input.refreshToken ?? null,
      input.slackUserId ?? null,
      CURRENT_SCOPE_VERSION,
    ],
  });
}

/**
 * Heal connections that an earlier (too-aggressive) scope-stale pass parked in
 * 'reconnect_required' but which still hold a valid token — flip them back to
 * 'connected' so syncing resumes. Safe one-time repair on boot.
 */
export async function reactivateReconnectRequired(): Promise<number> {
  const db = await getDb();
  const res = await db.execute({
    sql: `UPDATE calendar_connections SET status = 'connected'
          WHERE status = 'reconnect_required' AND refresh_token IS NOT NULL`,
    args: [],
  });
  return res.rowsAffected ?? 0;
}

/** Fully clear a connection (used by disconnect): drop tokens + mark revoked. */
export async function clearConnection(email: string): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `UPDATE calendar_connections SET status = 'revoked', refresh_token = NULL, sync_token = NULL WHERE host_email = ?`,
    args: [email.toLowerCase()],
  });
}

/**
 * Find connections granted under an older scope set, so we can PROMPT the host to
 * reconnect (and pick up new scopes). Deliberately does NOT change status — the
 * existing token still works for already-granted scopes (e.g. calendar), so we
 * keep syncing and let the new scope (e.g. contacts) light up after they reconnect.
 * A hard halt is only for `disconnectCalendar` (user-initiated / required-scope cases).
 */
export async function listScopeStaleConnections(): Promise<CalendarConnection[]> {
  const db = await getDb();
  const stale = await db.execute({
    sql: `SELECT * FROM calendar_connections
          WHERE status = 'connected' AND (scope_version IS DISTINCT FROM ?)`,
    args: [CURRENT_SCOPE_VERSION],
  });
  return (stale.rows as unknown as CalendarConnection[]) ?? [];
}

// ─── Connect-prompt throttle ──────────────────────────────────
//
// We nudge hosts to (re)connect their calendar from two places: the boot
// scope-stale scan and the invite-create flow. Both go through this throttle so
// we never bombard. Keyed by host_email (not the connection row) so it also
// covers hosts who have never connected and have no calendar_connections row.

/** Default re-prompt window for the invite-time nudge. Pass Infinity for once-ever. */
export const CONNECT_PROMPT_THROTTLE_MS = 24 * 60 * 60 * 1000;

/** Epoch-ms of the last connect/reconnect prompt sent to this host, or null. */
export async function getLastConnectPromptAt(email: string): Promise<number | null> {
  const db = await getDb();
  const res = await db.execute({
    sql: `SELECT last_prompted_at FROM calendar_connect_prompts WHERE host_email = ? LIMIT 1`,
    args: [email.toLowerCase()],
  });
  const raw = (res.rows[0] as { last_prompted_at?: string } | undefined)?.last_prompted_at;
  if (!raw) return null;
  const t = Date.parse(raw);
  return Number.isNaN(t) ? null : t;
}

/**
 * True when we may prompt this host again. `throttleMs = Infinity` means
 * once-ever (used by the boot scan so a redeploy can't re-fire).
 */
export async function shouldPromptConnect(email: string, throttleMs = CONNECT_PROMPT_THROTTLE_MS): Promise<boolean> {
  const at = await getLastConnectPromptAt(email);
  if (at === null) return true;
  return Date.now() - at >= throttleMs;
}

/** Record that a connect/reconnect prompt was just sent to this host. */
export async function recordConnectPrompt(email: string, slackUserId: string | null, reason: 'connect' | 'reconnect'): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `INSERT INTO calendar_connect_prompts (host_email, slack_user_id, reason, last_prompted_at)
          VALUES (?, ?, ?, now()::text)
          ON CONFLICT (host_email) DO UPDATE SET
            slack_user_id = COALESCE(EXCLUDED.slack_user_id, calendar_connect_prompts.slack_user_id),
            reason = EXCLUDED.reason,
            last_prompted_at = now()::text`,
    args: [email.toLowerCase(), slackUserId, reason],
  });
}

export async function updateSyncState(email: string, syncToken: string | null): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `UPDATE calendar_connections SET sync_token = ?, last_synced_at = now()::text WHERE host_email = ?`,
    args: [syncToken, email.toLowerCase()],
  });
}

export async function markConnectionRevoked(email: string): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `UPDATE calendar_connections SET status = 'revoked' WHERE host_email = ?`,
    args: [email.toLowerCase()],
  });
}

export async function listActiveOAuthConnections(): Promise<CalendarConnection[]> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM calendar_connections WHERE status = 'connected' AND auth_mode = 'oauth' AND refresh_token IS NOT NULL`,
    args: [],
  });
  return (result.rows as unknown as CalendarConnection[]) ?? [];
}

