if (pathname === '/api/visitor/calendar/connect/start' && method === 'GET') {
  if (!isCalendarOAuthConfigured()) {
    json(res, 503, { error: 'Calendar OAuth is not configured.' });
    return true;
  }
  const stateParam = typeof query.s === 'string' ? query.s : undefined;
  const payload = verifyCalendarState(stateParam);
  if (!payload || !stateParam) {
    json(res, 400, { error: 'Invalid or expired connect link. Please reopen it from Slack.' });
    return true;
  }
  const url = buildCalendarAuthUrl(stateParam, payload.email);
  res.writeHead(302, { Location: url });
  res.end();
  return true;
}

// ── Calendar disconnect (Slack button → revoke + stop push) ──
if (pathname === '/api/visitor/calendar/connect/disconnect' && method === 'GET') {
  const payload = verifyCalendarState(typeof query.s === 'string' ? query.s : undefined);
  const finishHtml = (title: string, message: string, ok: boolean) => {
    res.writeHead(ok ? 200 : 400, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(`<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>${title}</title></head><body style="font-family:system-ui,sans-serif;text-align:center;padding:48px 20px;color:#1a1a1a"><div style="font-size:48px">${ok ? '✓' : '⚠️'}</div><h2>${title}</h2><p style="color:#555">${message}</p><p style="color:#999;font-size:14px">You can close this tab and return to Slack.</p></body></html>`);
  };
  if (!payload) {
    finishHtml('Link expired', 'This disconnect link is invalid or expired. Please reopen it from Slack.', false);
    return true;
  }
  try {
    await disconnectCalendar(payload.email);
    finishHtml('Calendar disconnected', 'We’ve stopped reading your calendar. Reconnect any time from Slack to resume automatic visitor passes.', true);
  } catch (err) {
    console.error('[Calendar] disconnect failed:', err);
    finishHtml('Something went wrong', 'We couldn’t complete the disconnect. Please try again from Slack.', false);
  }
  return true;
}

// ── Calendar OAuth connect: callback ──────────────────────
if (pathname === '/api/visitor/calendar/connect/callback' && method === 'GET') {
  const cb = query as Record<string, string | string[] | undefined>;
  const code = typeof cb.code === 'string' ? cb.code : undefined;
  const stateParam = typeof cb.state === 'string' ? cb.state : undefined;
  const errorParam = typeof cb.error === 'string' ? cb.error : undefined;

  const finishHtml = (title: string, message: string, ok: boolean) => {
    res.writeHead(ok ? 200 : 400, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(`<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>${title}</title></head><body style="font-family:system-ui,sans-serif;text-align:center;padding:48px 20px;color:#1a1a1a"><div style="font-size:48px">${ok ? '✓' : '⚠️'}</div><h2>${title}</h2><p style="color:#555">${message}</p><p style="color:#999;font-size:14px">You can close this tab and return to Slack.</p></body></html>`);
  };

  if (errorParam) {
    finishHtml('Connection cancelled', `Google sign-in was cancelled (${errorParam}).`, false);
    return true;
  }
  const payload = verifyCalendarState(stateParam);
  if (!code || !payload) {
    finishHtml('Link expired', 'This connect link is invalid or expired. Please reopen it from Slack.', false);
    return true;
  }
  try {
    const { refreshToken } = await exchangeCalendarCode(code);
    await upsertCalendarConnection({
      email: payload.email,
      slackUserId: payload.slackUserId,
      refreshToken,
    });
    if (!refreshToken) {
      // Google didn't return one (prior consent without prompt). Connection is
      // recorded but background sync needs a token — ask them to reconnect.
      finishHtml('Almost there', 'We connected your account but need to refresh permissions. Please tap Connect again from Slack.', false);
      return true;
    }
    // Register a push channel so changes arrive in seconds (no-op if webhooks
    // aren't configured — the poller covers it then).
    void ensureWatchForHost(payload.email).catch((err) => console.warn('[CalendarWatch] register on connect failed:', err));
    finishHtml('Calendar connected', 'New meetings you host with outside guests will now create visitor passes automatically.', true);
  } catch (err) {
    console.error('[Calendar] OAuth callback failed:', err);
    finishHtml('Something went wrong', 'We couldn’t complete the connection. Please try again from Slack.', false);
  }
  return true;
}

// ── Walk-in Registration ──────────────────────────────────

if ((pathname === '/visitor/register' || pathname === '/api/visitor/register') && method === 'POST') {
  const body = await readBodyJson(req);
  const visitorName = String(body.visitor_name ?? body.visitorName ?? '').trim();
  if (!visitorName) {
    json(res, 400, { error: 'visitor_name is required' });

