27	function audiences(): string[] {
28	  // Accept a comma list — web and the mobile Calendar app may present
29	  // different OAuth client ids for the same add-on. The Chrome extension
30	  // surface uses its own Web OAuth client id, carried in a separate var.
31	  return [
32	    ...(process.env.AUXILIO_WORKSPACE_OAUTH_CLIENT_ID ?? '').split(','),
33	    ...(process.env.AUXILIO_EXTENSION_OAUTH_CLIENT_ID ?? '').split(','),
34	  ]
35	    .map((a) => a.trim())
36	    .filter(Boolean);
