47	  const devEmail = process.env.ADDON_DEV_TRUST_EMAIL;
48	  if (devEmail && process.env.NODE_ENV !== 'production') {
49	    console.warn(`[AddonAuth] DEV bypass active — trusting ${devEmail} WITHOUT token verification.`);
50	    return {
51	      email: devEmail.toLowerCase(),
52	      name: devEmail.split('@')[0] ?? devEmail,
53	      hd: devEmail.split('@')[1],
54	    };
55	  }
56	
57	  const idToken = (bearer ?? '').replace(/^Bearer\s+/i, '').trim();
58	  if (!idToken) return null;
59	
60	  const aud = audiences();
61	  if (aud.length === 0) {
62	    console.warn('[AddonAuth] no audience configured (AUXILIO_WORKSPACE_OAUTH_CLIENT_ID / AUXILIO_EXTENSION_OAUTH_CLIENT_ID) — rejecting.');
63	    return null;
64	  }
65	
66	  try {
67	    const ticket = await verifierClient.verifyIdToken({ idToken, audience: aud });
68	    const payload = ticket.getPayload();
69	    if (!payload?.email || !payload.email_verified) return null;
70	    return {
71	      email: payload.email.toLowerCase(),
72	      name: payload.name?.trim() || payload.email,
73	      hd: payload.hd,
74	    };
75	  } catch (err) {
76	    // On an audience mismatch, decode the token's `aud` (without verifying) and
77	    // print it next to the configured list so the misconfig is obvious.
