/**
 * Auxilio Workspace add-on — caller authentication.
 *
 * The Calendar add-on (Apps Script) sends a Google OIDC ID token
 * (`ScriptApp.getIdentityToken()`) as a Bearer header on every card action. We
 * verify it against the add-on's OAuth client id(s) and trust the resulting
 * email as the host/organizer — never an organizer passed in the request body.
 *
 * Spec: spec/2026-06-16_calendar_addon_register_endpoint.md §3.
 * Calendar-only / identity scopes — never widen to Gmail/Drive (would trigger CASA).
 */

import { google } from 'googleapis';
import { createHmac, timingSafeEqual } from 'crypto';

// A bare client is enough for verifyIdToken (no credentials needed).
const verifierClient = new google.auth.OAuth2();

export interface AddonIdentity {
  /** Lowercased, verified email — the trusted host/organizer. */
  email: string;
  name: string;
  /** Google hosted-domain claim (future multi-tenant key). */
  hd?: string;
}

function audiences(): string[] {
  // Accept a comma list — web and the mobile Calendar app may present
  // different OAuth client ids for the same add-on. The Chrome extension
  // surface uses its own Web OAuth client id, carried in a separate var.
  return [
    ...(process.env.AUXILIO_WORKSPACE_OAUTH_CLIENT_ID ?? '').split(','),
    ...(process.env.AUXILIO_EXTENSION_OAUTH_CLIENT_ID ?? '').split(','),
  ]
    .map((a) => a.trim())
    .filter(Boolean);
}

/**
 * Verify the add-on's Bearer ID token. Returns the trusted identity, or null
 * when the token is missing/invalid/unverified or no audience is configured.
 */
export async function verifyAddonIdToken(bearer: string | undefined): Promise<AddonIdentity | null> {
  // DEV-ONLY bypass: exercise the /addon/* routes without minting a Google ID
  // token (the real token comes from the Apps Script add-on, which isn't built
  // yet). Inert in production and unless ADDON_DEV_TRUST_EMAIL is explicitly set.
  const devEmail = process.env.ADDON_DEV_TRUST_EMAIL;
  if (devEmail && process.env.NODE_ENV !== 'production') {
    console.warn(`[AddonAuth] DEV bypass active — trusting ${devEmail} WITHOUT token verification.`);
    return {
      email: devEmail.toLowerCase(),
      name: devEmail.split('@')[0] ?? devEmail,
      hd: devEmail.split('@')[1],
    };
  }

  const idToken = (bearer ?? '').replace(/^Bearer\s+/i, '').trim();
  if (!idToken) return null;

  const aud = audiences();
  if (aud.length === 0) {
    console.warn('[AddonAuth] no audience configured (AUXILIO_WORKSPACE_OAUTH_CLIENT_ID / AUXILIO_EXTENSION_OAUTH_CLIENT_ID) — rejecting.');
    return null;
  }

  try {
    const ticket = await verifierClient.verifyIdToken({ idToken, audience: aud });
    const payload = ticket.getPayload();
    if (!payload?.email || !payload.email_verified) return null;
    return {
      email: payload.email.toLowerCase(),
      name: payload.name?.trim() || payload.email,
      hd: payload.hd,
    };
  } catch (err) {
    // On an audience mismatch, decode the token's `aud` (without verifying) and
    // print it next to the configured list so the misconfig is obvious.
    let tokenAud = '?';
    try {
      const body = JSON.parse(Buffer.from(idToken.split('.')[1], 'base64url').toString());
      tokenAud = String(body.aud ?? '?');
    } catch { /* ignore */ }
    console.warn(
      `[AddonAuth] id-token verification failed. token.aud=${tokenAud} ; configured audiences=[${aud.join(', ')}]`,
    );
    console.warn('[AddonAuth] detail:', err);
    return null;
  }
}

// ─── Signed preview links ─────────────────────────────────────
// The HTML email preview opens in a browser popup (CardService OpenLink), which
// can't carry the Bearer ID token. We authorize that GET with a short-lived
// HMAC-signed token instead. Payload is non-sensitive (iCalUid + email + exp).

function previewSecret(): string {
  return process.env.VISITOR_ADMIN_SESSION_SECRET
    ?? process.env.VISITOR_ADMIN_SECRET
    ?? 'auxilio-addon-preview-fallback';
}

export function signPreviewToken(payload: Record<string, unknown>): string {
  const body = Buffer.from(JSON.stringify(payload)).toString('base64url');
  const sig = createHmac('sha256', previewSecret()).update(body).digest('base64url');
  return `${body}.${sig}`;
}

export function verifyPreviewToken(token: string | undefined): Record<string, unknown> | null {
  const [body, sig] = (token ?? '').split('.');
  if (!body || !sig) return null;
  const expected = createHmac('sha256', previewSecret()).update(body).digest('base64url');
  const a = Buffer.from(sig);
  const b = Buffer.from(expected);
  if (a.length !== b.length || !timingSafeEqual(a, b)) return null;
  try {
    const payload = JSON.parse(Buffer.from(body, 'base64url').toString()) as Record<string, unknown>;
    if (typeof payload.exp === 'number' && Date.now() > payload.exp) return null;
    return payload;
  } catch {
    return null;
  }
}

/**
 * Domain gate — only internal-domain hosts may register visits (internal-first).
 * Reuses the same env the calendar pipeline uses. Empty allowlist → allow (dev).
 */
export function isInternalHostEmail(email: string): boolean {
  const domains = (process.env.VISITOR_CALENDAR_INTERNAL_DOMAINS ?? process.env.GOOGLE_CALENDAR_DOMAIN ?? '')
    .split(',')
    .map((d) => d.trim().toLowerCase())
    .filter(Boolean);
  if (domains.length === 0) return true;
  const domain = email.split('@')[1]?.toLowerCase() ?? '';
  return domains.includes(domain);
}

