1	import {
2	  ACTIVE_EID_KEY,
3	  ACTIVE_SNAPSHOT_KEY,
4	  NUDGE_TARGETS,
5	  PANEL_STATE,
6	  SIDEPANEL_PORT,
7	  broadcastRefreshActive,
8	  type RpcRequest,
9	  type RpcResponse,
10	} from '@/lib/messaging';
11	import { authStatus, getValidTokens, signIn, signOut } from '@/lib/auth';
12	import { decodeEid, encodeEid, fetchActiveEvent } from '@/lib/calendar';
13	import { listMarked, runSync } from '@/lib/calendar-sync';
14	import { EngineError, engine } from '@/lib/engine';
15	import type { VisitorEventSummary } from '@/lib/types';
16	
17	const SYNC_ALARM = 'auxilio-sync';
18	const BADGE_COLOR = '#92288E';
19	
20	// Whether the side panel is currently open (a port is connected). Content
21	// scripts ask for this on (re)load so auto-follow works after navigation.
22	let panelConnected = false;
23	
24	export default defineBackground(() => {
25	  // Let content scripts read/write storage.session (default is trusted-only).
26	  // Needed for the active-event handoff + nudge-dismissal persistence.
27	  chrome.storage.session
28	    .setAccessLevel({ accessLevel: 'TRUSTED_AND_UNTRUSTED_CONTEXTS' })
29	    .catch((err) => console.warn('[auxilio] setAccessLevel failed', err));
30	
31	  // Toolbar icon opens the panel (Chrome's required user gesture).
32	  chrome.sidePanel
33	    .setPanelBehavior({ openPanelOnActionClick: true })
34	    .catch((err) => console.error('[auxilio] setPanelBehavior failed', err));
35	
36	  // Durable, official change-detection: poll on an alarm (no DOM).
37	  chrome.alarms.create(SYNC_ALARM, { periodInMinutes: 1 });
38	  chrome.runtime.onInstalled.addListener(() =>
39	    chrome.alarms.create(SYNC_ALARM, { periodInMinutes: 1 }),
40	  );
41	  chrome.runtime.onStartup.addListener(() => void doSync());
42	  chrome.alarms.onAlarm.addListener((a) => {
43	    if (a.name === SYNC_ALARM) void doSync();
44	  });
45	  chrome.notifications.onClicked.addListener((id) => chrome.notifications.clear(id));
46	
47	  // Track the side panel open/closed via a port it connects on mount, and tell
48	  // calendar tabs so the in-page button can hide while the panel is open.
49	  chrome.runtime.onConnect.addListener((port) => {
50	    if (port.name !== SIDEPANEL_PORT) return;
51	    panelConnected = true;
52	    broadcastPanelState(true);
53	    port.onDisconnect.addListener(() => {
54	      panelConnected = false;
55	      broadcastPanelState(false);
56	    });
57	  });
58	
59	  chrome.runtime.onMessage.addListener((msg: RpcRequest, sender, sendResponse) => {
60	    if (typeof msg?.type === 'string' && msg.type.startsWith('__')) return false; // broadcasts
61	    handle(msg, sender)
62	      .then(sendResponse)
63	      .catch((err) => sendResponse(fail(err)));
64	    return true; // async response
65	  });
66	
67	  console.log('[auxilio] background ready');
68	});
69	
70	// ─────────────────────────── sync loop ───────────────────────────
71	
72	async function doSync(): Promise<void> {
73	  let accessToken: string;
74	  try {
75	    accessToken = (await getValidTokens()).accessToken;
76	  } catch {
77	    return; // not signed in — nothing to poll
78	  }
79	  let result;
80	  try {
81	    result = await runSync(accessToken);
82	  } catch (err) {
83	    console.warn('[auxilio] sync failed', err);
84	    return;
85	  }
86	
87	  // Toolbar badge = number of upcoming visitor events (the on-icon nudge).
88	  await chrome.action.setBadgeBackgroundColor({ color: BADGE_COLOR });
89	  await chrome.action.setBadgeText({
90	    text: result.markedCount > 0 ? String(result.markedCount) : '',
91	  });
92	
93	  // OS notification for each newly-discovered visitor event (out-of-tab alert).
94	  for (const ev of result.newMarked) notifyVisitorEvent(ev);
95	
96	  // In-page nudge banner: push the current marked set to calendar tabs, plus
97	  // any events that just stopped being pending (deleted/cancelled) so the page
98	  // can purge stale optimistic nudges for them.
99	  broadcastNudge(await listMarked(), result.cancelledIds);
100	
101	  // If the event the panel is showing changed (post-save), tell it to refetch.
102	  const stored = await chrome.storage.session.get(ACTIVE_EID_KEY);
103	  const activeEid = stored[ACTIVE_EID_KEY] as string | undefined;
104	  if (activeEid) {
105	    const dec = decodeEid(activeEid);
106	    if (dec && result.changedIds.has(dec.eventId)) broadcastRefreshActive();
107	  }
108	}
109	
110	function broadcastPanelState(open: boolean): void {
111	  sendToCalendarTabs({ type: PANEL_STATE, open });
112	}
113	
114	function broadcastNudge(targets: VisitorEventSummary[], cancelled: string[] = []): void {
115	  sendToCalendarTabs({ type: NUDGE_TARGETS, targets, cancelled });
116	}
117	
118	function sendToCalendarTabs(message: unknown): void {
119	  chrome.tabs
120	    .query({ url: 'https://calendar.google.com/*' })
121	    .then((tabs) => {
122	      for (const t of tabs) {
123	        if (t.id != null) chrome.tabs.sendMessage(t.id, message).catch(() => {});
124	      }
125	    })
126	    .catch(() => {});
127	}
128	
129	function notifyVisitorEvent(ev: VisitorEventSummary): void {
130	  chrome.notifications.create(`auxilio:${ev.eventId}`, {
131	    type: 'basic',
132	    iconUrl: chrome.runtime.getURL('icon/128.png'),
133	    title: 'Visitor event',
134	    message: `${ev.title} — open Auxilio to register passes`,
135	    priority: 1,
136	  });
137	}
138	
139	// ─────────────────────────── RPC plumbing ───────────────────────────
140	
