1	/**
2	 * Typed RPC over chrome.runtime messaging. The side panel (and content script)
3	 * never touch tokens or the network directly — they send these messages and the
4	 * background worker does the work. This keeps the thin-adapter boundary: one
5	 * place holds secrets + network.
6	 */
7	import type {
8	  ActiveEvent,
9	  AuthStatus,
10	  DomEventSnapshot,
11	  DraftPatch,
12	  DraftResponse,
13	  PreviewResponse,
14	  SendResponse,
15	  VisitDraft,
16	  VisitorEventSummary,
17	} from './types';
18	
19	export type RpcRequest =
20	  | { type: 'AUTH_STATUS' }
21	  | { type: 'AUTH_SIGN_IN' }
22	  | { type: 'AUTH_SIGN_OUT' }
23	  | { type: 'OPEN_FOR_EVENT'; eid: string; snapshot?: DomEventSnapshot }
24	  | { type: 'FOLLOW_EVENT'; eid: string; snapshot?: DomEventSnapshot }
25	  | { type: 'RESOLVE_EVENT'; eid: string }
26	  | { type: 'DRAFT_LOAD'; event: ActiveEvent }
27	  | { type: 'DRAFT_PATCH'; iCalUid: string; patch: DraftPatch }
28	  | { type: 'PREVIEW'; iCalUid: string; visitorEmail: string }
29	  | { type: 'SEND'; iCalUid: string; start?: string; end?: string }
30	  | { type: 'CANCEL_GUEST'; iCalUid: string; invitationId: string }
31	  | { type: 'LIST_VISITOR_EVENTS' }
32	  | { type: 'GET_NUDGE_TARGETS' }
33	  | { type: 'SYNC_NOW' }
34	  | { type: 'GET_PANEL_STATE' }
35	  | { type: 'NAVIGATE_TO_EVENT'; eventId?: string; eid?: string };
36	
37	/** Maps each request type to its success payload. */
38	export interface RpcResultMap {
39	  AUTH_STATUS: AuthStatus;
40	  AUTH_SIGN_IN: AuthStatus;
41	  AUTH_SIGN_OUT: { signedIn: false };
42	  OPEN_FOR_EVENT: { opened: boolean };
43	  FOLLOW_EVENT: { followed: boolean };
44	  RESOLVE_EVENT: ActiveEvent;
45	  DRAFT_LOAD: DraftResponse;
46	  DRAFT_PATCH: VisitDraft;
47	  PREVIEW: PreviewResponse;
48	  SEND: SendResponse;
49	  CANCEL_GUEST: { invitationId: string; cancelled: boolean };
50	  LIST_VISITOR_EVENTS: VisitorEventSummary[];
51	  GET_NUDGE_TARGETS: VisitorEventSummary[];
52	  SYNC_NOW: { synced: boolean };
53	  GET_PANEL_STATE: { open: boolean };
54	  NAVIGATE_TO_EVENT: { navigated: boolean };
55	}
56	
57	export type RpcResponse<T> =
58	  | { ok: true; data: T }
59	  | { ok: false; error: string; status?: number; needsAuth?: boolean };
60	
61	export class RpcError extends Error {
62	  constructor(
63	    message: string,
64	    readonly status?: number,
65	    readonly needsAuth?: boolean,
66	  ) {
67	    super(message);
68	    this.name = 'RpcError';
69	  }
70	}
71	
72	/** Side-panel-side caller: throws RpcError on failure, returns typed data. */
73	export async function rpc<K extends RpcRequest['type']>(
74	  msg: Extract<RpcRequest, { type: K }>,
75	): Promise<RpcResultMap[K]> {
76	  const res = (await chrome.runtime.sendMessage(msg)) as
77	    | RpcResponse<RpcResultMap[K]>
78	    | undefined;
79	  if (!res) throw new RpcError('No response from background worker');
80	  if (!res.ok) throw new RpcError(res.error, res.status, res.needsAuth);
81	  return res.data;
82	}
83	
84	/** storage.session key holding the pending event id (set by background on the
85	 *  content-script button click, read reactively by the side panel). */
86	export const ACTIVE_EID_KEY = 'auxilio.activeEid';
87	
88	/** storage.session key holding the DOM snapshot for the pending event — lets the
89	 *  panel paint instantly + handle the unsaved (no-API) case. */
90	export const ACTIVE_SNAPSHOT_KEY = 'auxilio.activeSnapshot';
91	
92	/** Background→content broadcast of side-panel open state, so the in-page button
93	 *  hides while the panel is open (no redundant control). */
94	export const PANEL_STATE = '__auxilio_panel_state';
95	
96	/** Port name the side panel connects on mount so background can track open/close. */
97	export const SIDEPANEL_PORT = 'auxilio.sidepanel';
98	
99	/** Background→content broadcast of the visitor events needing passes (drives the
100	 *  in-page nudge banner). */
101	export const NUDGE_TARGETS = '__auxilio_nudge_targets';
102	
103	/** One-way background→panel broadcast: the active event changed on the server
104	 *  (post-save), so the panel should refetch. Not an RPC (no response). */
105	export const REFRESH_ACTIVE = '__auxilio_refresh_active';
106	
107	export function broadcastRefreshActive(): void {
108	  chrome.runtime.sendMessage({ type: REFRESH_ACTIVE }).catch(() => {});
109	}
