export async function ensureWatchForHost(email: string): Promise<void> {
  if (!webhookOrigin()) return;
  const fresh = (await listChannelsForHost(email)).some((c) => c.expiration && c.expiration > Date.now() + RENEW_BEFORE_MS);
  if (fresh) return;
  const conn = await getCalendarConnection(email);
  if (conn?.refresh_token && conn.status === 'connected') await registerWatch(conn);
}

async function stopChannel(channel: WatchChannelRow): Promise<void> {
  const conn = await getCalendarConnection(channel.host_email);
  if (conn?.refresh_token) {
    try {
      const calendar = google.calendar({ version: 'v3', auth: clientForRefreshToken(conn.refresh_token) });
      await calendar.channels.stop({ requestBody: { id: channel.channel_id, resourceId: channel.resource_id } });
    } catch (err: any) {
      // Best-effort; an already-expired channel will 404 — fine.
      console.warn(`[CalendarWatch] stop channel ${channel.channel_id} failed:`, err?.message ?? err);
    }
  }
  await deleteChannel(channel.channel_id);
}

/** Re-register channels nearing expiry; stop the stale ones. */
export async function renewExpiringWatches(): Promise<void> {
  if (!webhookOrigin()) return;
  const soon = Date.now() + RENEW_BEFORE_MS;
  for (const ch of await listAllChannels()) {
    if (ch.expiration && ch.expiration >= soon) continue;
    const conn = await getCalendarConnection(ch.host_email);
    if (conn?.refresh_token && conn.status === 'connected') {
      await registerWatch(conn); // new channel (new row)
    }
    await stopChannel(ch);        // retire the old one
  }
}

