/**
 * Centralized configuration from environment variables.
 * All env access goes through this module — never read process.env directly elsewhere.
 */

function env(key: string, fallback?: string): string {
  const value = process.env[key] ?? fallback;
  if (value === undefined) {
    throw new Error(`Missing required environment variable: ${key}`);
  }
  return value;
}

function envOptional(key: string): string | undefined {
  return process.env[key] || undefined;
}

function envList(key: string): string[] {
  const raw = process.env[key];
  if (!raw) return [];
  return raw.split(',').map(s => s.trim()).filter(Boolean);
}

function envNumberList(key: string): number[] {
  return envList(key)
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value));
}

// ─── Telegram ──────────────────────────────────────────────

function envFlag(value: string | undefined): boolean | undefined {
  if (value === undefined) return undefined;
  const normalized = value.trim().toLowerCase();
  if (['1', 'true', 'yes', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'no', 'off'].includes(normalized)) return false;
  return undefined;
}

export const telegram = {
  // Master switch for all Telegram I/O (channel + log transport).
  // Explicit TELEGRAM_ENABLED wins; otherwise defaults on when a token is present.
  enabled: () => {
