/**
 * Calendar sync poller — the OAuth-path detection pipeline.
 *
 * Canonical design: Planning-docs/2026-06-12_calendar_to_visitor_invite_research.md §8.
 *
 * Per connected host, incrementally pull calendar changes with a `syncToken` cursor
 * (cheaper + simpler than push/watch channels, tolerant of patchy connectivity — fits
 * the cost/infrastructure constraints), normalize each event, and feed it into the
 * shared `ingestCalendarEvent` spine as source 'oauth'. Dedup on iCalUID in the spine
 * keeps this from double-creating with the magic-address path.
 *
 * False-positive guard (research doc §2): we only ingest events the host actually
 * ORGANIZES — a host being invited to someone else's (often remote) meeting must not
 * mint visitor passes for that meeting's other external guests. A proper in-person
 * signal (a reception resource on the event) is the eventual refinement.
 */

import type { calendar_v3 } from 'googleapis';
import { google } from 'googleapis';
import {
  clientForRefreshToken,
  listActiveOAuthConnections,
  getCalendarConnection,
  updateSyncState,
  markConnectionRevoked,
  type CalendarConnection,
} from './calendar-oauth';
import { ingestCalendarEvent, type NormalizedCalendarEvent } from './calendar-ingest';

let loopHandle: ReturnType<typeof setInterval> | null = null;
let running = false;
const SYNC_DEBUG = process.env.VISITOR_CALENDAR_SYNC_DEBUG === '1';

function syncIntervalMs(): number {
  const raw = Number(process.env.VISITOR_CALENDAR_SYNC_INTERVAL_MS);
  if (Number.isFinite(raw) && raw >= 60_000) return raw;
  // When push/webhooks are configured, polling is just a safety net for missed
  // notifications, so back it off to hourly. Otherwise poll every 5 min.
  return process.env.VISITOR_CALENDAR_WEBHOOK_ORIGIN ? 60 * 60_000 : 5 * 60_000;
}

function toNormalized(
  event: calendar_v3.Schema$Event,
  hostEmail: string,
  hostName: string | undefined,
): NormalizedCalendarEvent {
  const attendees = (event.attendees ?? [])
    .filter((a) => !a.resource && a.email)
    .map((a) => ({ email: String(a.email), name: a.displayName ?? undefined }));

  const startRaw = event.start?.dateTime ?? event.start?.date ?? undefined;
  const endRaw = event.end?.dateTime ?? event.end?.date ?? undefined;

  return {
    iCalUid: event.iCalUID ?? event.id ?? '',
    providerEventId: event.id ?? undefined,
    sequence: event.sequence ?? 0,
    method: event.status === 'cancelled' ? 'CANCEL' : 'REQUEST',
    title: event.summary ?? undefined,
    // OAuth path: the connected user IS the host, regardless of organizer field.
    organizer: { email: hostEmail, name: hostName },
    attendees,
    start: startRaw ? new Date(startRaw) : undefined,
    end: endRaw ? new Date(endRaw) : undefined,
    location: event.location ?? undefined,
    source: 'oauth',
  };
}


/** True when the connected host is the event organizer (false-positive guard). */
function hostOrganizesEvent(event: calendar_v3.Schema$Event, hostEmail: string): boolean {
  if (event.organizer?.self) return true;
  return event.organizer?.email?.toLowerCase() === hostEmail.toLowerCase();
}

async function syncConnection(conn: CalendarConnection): Promise<void> {
  if (!conn.refresh_token) return;
  const hostEmail = conn.host_email;
  const client = clientForRefreshToken(conn.refresh_token);
  const calendar = google.calendar({ version: 'v3', auth: client });

  let pageToken: string | undefined;
  let syncToken: string | null = conn.sync_token;
  let nextSyncToken: string | null = null;
  let totalItems = 0;
  const counts: Record<string, number> = { notOrganized: 0 };

  try {
    do {
      const params: calendar_v3.Params$Resource$Events$List = {
        calendarId: 'primary',
        singleEvents: true, // expand recurrence → Google handles RRULE for us
        showDeleted: true,  // so cancellations arrive as status:'cancelled'
        maxResults: 250,
        pageToken,
      };
      if (syncToken) {
        params.syncToken = syncToken;
      } else {
        // Fresh sync: only care about upcoming visits. Do NOT set orderBy — it
        // suppresses nextSyncToken, which would force a full re-sync every pass.
        params.timeMin = new Date().toISOString();
      }

      let res;
      try {
        res = await calendar.events.list(params);
      } catch (err: any) {
        // 410 GONE → syncToken expired; restart with a full sync next pass.
        if (err?.code === 410 || err?.response?.status === 410) {
          await updateSyncState(hostEmail, null);
          return;
        }
        throw err;
      }

      const items = res.data.items ?? [];
      for (const event of items) {
        if (!event.iCalUID && !event.id) continue;
        // Only host-organized events (skip meetings the host was merely invited to).
        if (event.status !== 'cancelled' && !hostOrganizesEvent(event, hostEmail)) {
          counts.notOrganized = (counts.notOrganized ?? 0) + 1;
          continue;
        }
        try {
          const normalized = toNormalized(event, hostEmail, undefined);
          // (Name enrichment via contacts removed — names come from the add-on /
          // invite forms now; the poll no longer creates invites. See consolidation plan.)
          const result = await ingestCalendarEvent(normalized, { tenantId: conn.tenant_id });
          counts[result.status] = (counts[result.status] ?? 0) + 1;
          // Only log actionable outcomes; skips/duplicates are summarized below.
          if (result.status === 'created' || result.status === 'cancelled' || result.status === 'updated') {
            console.log(`[CalendarSync] ${hostEmail}: "${event.summary ?? ''}" → ${result.status}${result.reason ? ` (${result.reason})` : ''} (invites=${result.invitationIds.length})`);
          } else if (SYNC_DEBUG) {
            console.log(`[CalendarSync] ${hostEmail}: "${event.summary ?? ''}" → ${result.status}${result.reason ? ` (${result.reason})` : ''}`);
          }
          // Note: no-auto-send — ingestCalendarEvent now builds the Visit Draft for
          // every source itself (status 'drafted'); no separate pre-warm needed here.
        } catch (e) {
          console.warn(`[CalendarSync] ingest failed for ${hostEmail} event ${event.id}:`, e);
        }
      }
      totalItems += items.length;

      pageToken = res.data.nextPageToken ?? undefined;
      if (res.data.nextSyncToken) nextSyncToken = res.data.nextSyncToken;
    } while (pageToken);

    // One summary line per pass instead of one line per event.
    if (totalItems > 0 || SYNC_DEBUG) {
      const parts = Object.entries(counts).filter(([, n]) => n > 0).map(([k, n]) => `${k}=${n}`).join(' ');
      console.log(`[CalendarSync] ${hostEmail}: ${totalItems} change(s)${parts ? ` (${parts})` : ''} — ${nextSyncToken ? 'cursor saved' : 'no cursor'}`);
    }

    if (nextSyncToken) await updateSyncState(hostEmail, nextSyncToken);
  } catch (err: any) {
    const reason = err?.response?.data?.error ?? err?.message ?? '';
    if (String(reason).includes('invalid_grant')) {
      // Refresh token revoked/expired → mark revoked so the bot can re-prompt.
      console.warn(`[CalendarSync] ${hostEmail} refresh token invalid — marking revoked`);
      await markConnectionRevoked(hostEmail).catch(() => {});
      return;
    }
    console.error(`[CalendarSync] sync failed for ${hostEmail}:`, err?.message ?? err);
  }
}

/** Sync a single host on demand (used by the push-notification webhook). */
export async function syncHostByEmail(email: string): Promise<void> {
  const conn = await getCalendarConnection(email);
  if (conn && conn.status === 'connected' && conn.refresh_token) {
    await syncConnection(conn);
  }
}

/** Run one sync pass across all connected hosts. Exposed for manual triggering/tests. */
export async function runCalendarSyncOnce(): Promise<{ connections: number }> {
  if (running) return { connections: 0 };
  running = true;
  try {
    const connections = await listActiveOAuthConnections();
    for (const conn of connections) {
      await syncConnection(conn);
    }
    return { connections: connections.length };
  } finally {
    running = false;
  }
}

/** Start the background poll loop. Idempotent; no-op if OAuth path isn't configured. */
export function startCalendarSyncLoop(): void {
  if (loopHandle) return;
  if (process.env.VISITOR_CALENDAR_SYNC_DISABLED === '1') return;
  const interval = syncIntervalMs();
  loopHandle = setInterval(() => {
    runCalendarSyncOnce().catch((e) => console.error('[CalendarSync] loop error:', e));
  }, interval);
  if (typeof loopHandle.unref === 'function') loopHandle.unref();
  console.log(`[CalendarSync] poll loop started (every ${Math.round(interval / 1000)}s)`);
}

export function stopCalendarSyncLoop(): void {
  if (loopHandle) {
    clearInterval(loopHandle);
    loopHandle = null;
  }
}

