import { randomUUID } from 'crypto';
import { google } from 'googleapis';
import { getDb } from '../../lib/database';
import {
  clientForRefreshToken,
  getCalendarConnection,
  listActiveOAuthConnections,
  clearConnection,
  type CalendarConnection,
} from './calendar-oauth';
import { syncHostByEmail } from './calendar-sync';

const WATCH_TTL_MS = 7 * 24 * 60 * 60 * 1000; // request a week; Google may shorten
const RENEW_BEFORE_MS = 24 * 60 * 60 * 1000;  // renew when <24h remain
const RENEW_INTERVAL_MS = 6 * 60 * 60 * 1000; // check for renewals every 6h

let renewHandle: ReturnType<typeof setInterval> | null = null;

function webhookOrigin(): string | null {
  return (process.env.VISITOR_CALENDAR_WEBHOOK_ORIGIN ?? '').replace(/\/$/, '') || null;
}
export function isCalendarWebhookConfigured(): boolean {
  return !!webhookOrigin();
}
function webhookUrl(): string {
  return `${webhookOrigin()}/api/visitor/calendar/notifications`;
}
function channelToken(): string {
  return process.env.VISITOR_CALENDAR_WEBHOOK_SECRET
    ?? process.env.VISITOR_CALENDAR_INBOUND_SECRET
    ?? 'calendar-webhook-token';
}

// ─── Channel store ────────────────────────────────────────────

interface WatchChannelRow {
  channel_id: string;
  resource_id: string;
  host_email: string;
  expiration: number | null;
}

async function saveChannel(row: { channelId: string; resourceId: string; hostEmail: string; expiration: number }): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `INSERT INTO calendar_watch_channels (channel_id, resource_id, host_email, expiration)
          VALUES (?, ?, ?, ?)
          ON CONFLICT (channel_id) DO UPDATE SET resource_id = EXCLUDED.resource_id, expiration = EXCLUDED.expiration`,
    args: [row.channelId, row.resourceId, row.hostEmail.toLowerCase(), row.expiration],
  });
}

async function getChannelHost(channelId: string): Promise<string | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT host_email FROM calendar_watch_channels WHERE channel_id = ? LIMIT 1`,
    args: [channelId],
  });
  const row = result.rows[0] as unknown as { host_email: string } | undefined;
  return row?.host_email ?? null;
}

async function listChannelsForHost(email: string): Promise<WatchChannelRow[]> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT channel_id, resource_id, host_email, expiration FROM calendar_watch_channels WHERE host_email = ?`,
    args: [email.toLowerCase()],
  });
  return (result.rows as unknown as WatchChannelRow[]) ?? [];
}

async function listAllChannels(): Promise<WatchChannelRow[]> {
  const db = await getDb();
  const result = await db.execute({ sql: `SELECT channel_id, resource_id, host_email, expiration FROM calendar_watch_channels`, args: [] });
  return (result.rows as unknown as WatchChannelRow[]) ?? [];
}

async function deleteChannel(channelId: string): Promise<void> {
  const db = await getDb();
  await db.execute({ sql: `DELETE FROM calendar_watch_channels WHERE channel_id = ?`, args: [channelId] });
}

// ─── Register / renew / stop ──────────────────────────────────

export async function registerWatch(conn: CalendarConnection): Promise<void> {
  if (!conn.refresh_token || !webhookOrigin()) return;
  const calendar = google.calendar({ version: 'v3', auth: clientForRefreshToken(conn.refresh_token) });
  const channelId = randomUUID();
  const requested = Date.now() + WATCH_TTL_MS;
  try {
    const res = await calendar.events.watch({
      calendarId: 'primary',
      requestBody: { id: channelId, type: 'web_hook', address: webhookUrl(), token: channelToken(), expiration: String(requested) },
    });
    const resourceId = res.data.resourceId;
    if (!resourceId) {
      console.warn(`[CalendarWatch] no resourceId returned for ${conn.host_email}`);
      return;
    }
    const expiration = res.data.expiration ? Number(res.data.expiration) : requested;
    await saveChannel({ channelId, resourceId, hostEmail: conn.host_email, expiration });
    console.log(`[CalendarWatch] watch on for ${conn.host_email}, expires ${new Date(expiration).toISOString()}`);
  } catch (err: any) {
    console.error(`[CalendarWatch] watch failed for ${conn.host_email}:`, err?.response?.data?.error ?? err?.message ?? err);
  }
}

/** Register a watch for a host only if they don't already have a fresh channel. */
export async function ensureWatchForHost(email: string): Promise<void> {
  if (!webhookOrigin()) return;
  const fresh = (await listChannelsForHost(email)).some((c) => c.expiration && c.expiration > Date.now() + RENEW_BEFORE_MS);
  if (fresh) return;
  const conn = await getCalendarConnection(email);
  if (conn?.refresh_token && conn.status === 'connected') await registerWatch(conn);
}

async function stopChannel(channel: WatchChannelRow): Promise<void> {
  const conn = await getCalendarConnection(channel.host_email);
  if (conn?.refresh_token) {
    try {
      const calendar = google.calendar({ version: 'v3', auth: clientForRefreshToken(conn.refresh_token) });
      await calendar.channels.stop({ requestBody: { id: channel.channel_id, resourceId: channel.resource_id } });
    } catch (err: any) {
      // Best-effort; an already-expired channel will 404 — fine.
      console.warn(`[CalendarWatch] stop channel ${channel.channel_id} failed:`, err?.message ?? err);
    }
  }
  await deleteChannel(channel.channel_id);
}

/** Re-register channels nearing expiry; stop the stale ones. */
export async function renewExpiringWatches(): Promise<void> {
  if (!webhookOrigin()) return;
  const soon = Date.now() + RENEW_BEFORE_MS;
  for (const ch of await listAllChannels()) {
    if (ch.expiration && ch.expiration >= soon) continue;
    const conn = await getCalendarConnection(ch.host_email);
    if (conn?.refresh_token && conn.status === 'connected') {
      await registerWatch(conn); // new channel (new row)
    }
    await stopChannel(ch);        // retire the old one
  }
