  await stopWatchesForHost(email).catch((e) => console.warn(`[CalendarWatch] stop watches on disconnect failed for ${email}:`, e));
  const conn = await getCalendarConnection(email);
  if (conn?.refresh_token) {
    try {
      await clientForRefreshToken(conn.refresh_token).revokeCredentials();
    } catch (e: any) {
      // Token may already be invalid — fine, we still clear our side.
      console.warn(`[CalendarWatch] revoke on disconnect failed for ${email}:`, e?.message ?? e);
    }
  }
  await clearConnection(email);
  console.log(`[CalendarWatch] disconnected calendar for ${email}`);
}

// ─── Notification handling ────────────────────────────────────

/** Handle one inbound Google push. Verifies token, maps channel→host, syncs that host. */
export async function handleCalendarNotification(headers: Record<string, string | string[] | undefined>): Promise<void> {
