  const conn = await getCalendarConnection(email);
  if (conn?.refresh_token && conn.status === 'connected') await registerWatch(conn);
}

async function stopChannel(channel: WatchChannelRow): Promise<void> {
  const conn = await getCalendarConnection(channel.host_email);
  if (conn?.refresh_token) {
    try {
      const calendar = google.calendar({ version: 'v3', auth: clientForConnection(conn) });
      await calendar.channels.stop({ requestBody: { id: channel.channel_id, resourceId: channel.resource_id } });
    } catch (err: any) {
      // Best-effort; an already-expired channel will 404 — fine.
      console.warn(`[CalendarWatch] stop channel ${channel.channel_id} failed:`, err?.message ?? err);
    }
  }
  await deleteChannel(channel.channel_id);
}

/** Re-register channels nearing expiry; stop the stale ones. */
export async function renewExpiringWatches(): Promise<void> {
  if (!webhookOrigin()) return;
  const soon = Date.now() + RENEW_BEFORE_MS;
  for (const ch of await listAllChannels()) {
    if (ch.expiration && ch.expiration >= soon) continue;
    const conn = await getCalendarConnection(ch.host_email);
    if (conn?.refresh_token && conn.status === 'connected') {
      await registerWatch(conn); // new channel (new row)
    }
    await stopChannel(ch);        // retire the old one
  }
}

/** Ensure every connected host has a live watch (called on boot). */
export async function ensureAllWatches(): Promise<void> {
  if (!webhookOrigin()) return;
  for (const conn of await listActiveOAuthConnections()) {
    await ensureWatchForHost(conn.host_email);
  }
}

/** Stop + delete all watch channels for a host (used by disconnect). */
export async function stopWatchesForHost(email: string): Promise<void> {
  for (const ch of await listChannelsForHost(email)) {
    await stopChannel(ch);
  }
}

/**
 * Fully disconnect a host's calendar: stop push channels, revoke the token at
 * Google (best-effort), and clear the stored connection. After this the Slack UI
 * shows "Connect" again. Used by the Slack Disconnect button and programmatically.
 */
export async function disconnectCalendar(email: string): Promise<void> {
  await stopWatchesForHost(email).catch((e) => console.warn(`[CalendarWatch] stop watches on disconnect failed for ${email}:`, e));
  const conn = await getCalendarConnection(email);
  if (conn?.refresh_token) {
    try {
      await clientForRefreshToken(conn.refresh_token).revokeCredentials();
    } catch (e: any) {
      // Token may already be invalid — fine, we still clear our side.
      console.warn(`[CalendarWatch] revoke on disconnect failed for ${email}:`, e?.message ?? e);
    }
  }
  await clearConnection(email);
  console.log(`[CalendarWatch] disconnected calendar for ${email}`);
}

// ─── Notification handling ────────────────────────────────────

/** Handle one inbound Google push. Verifies token, maps channel→host, syncs that host. */
export async function handleCalendarNotification(headers: Record<string, string | string[] | undefined>): Promise<void> {
  const get = (k: string) => {
    const v = headers[k];
    return Array.isArray(v) ? v[0] : v;
  };
  if (get('x-goog-channel-token') !== channelToken()) {
    console.warn('[CalendarWatch] notification rejected: bad channel token');
    return;
  }
  const state = get('x-goog-resource-state');
  if (state === 'sync') return; // initial handshake right after channel creation — ignore
  const channelId = get('x-goog-channel-id');
  if (!channelId) return;
  const host = await getChannelHost(channelId);
  if (!host) {
    console.warn(`[CalendarWatch] notification for unknown channel ${channelId}`);
    return;
  }
  await syncHostByEmail(host);
}

// ─── Renewal loop ─────────────────────────────────────────────

export function startWatchRenewalLoop(): void {
  if (renewHandle || !webhookOrigin()) return;
  renewHandle = setInterval(() => {
    renewExpiringWatches().catch((e) => console.error('[CalendarWatch] renewal error:', e));
  }, RENEW_INTERVAL_MS);
  if (typeof renewHandle.unref === 'function') renewHandle.unref();
  console.log('[CalendarWatch] renewal loop started');
}

export function stopWatchRenewalLoop(): void {
  if (renewHandle) {
    clearInterval(renewHandle);
    renewHandle = null;
  }
}

